{
  "name": "CrateTrack SA",
  "description": "A comprehensive South African industrial asset tracking system for crates and pallets, featuring historical fee versioning, THAAN slip management, and logistics batch movements.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum LocationType {
  CRATES_DEPT = 'Crates Dept',
  WAREHOUSE = 'Warehouse',
  AT_CUSTOMER = 'At Customer',
  IN_TRANSIT = 'In Transit',
  RETURNING = 'Returning to Supplier'
}

export enum AssetType {
  CRATE = 'Crate',
  PALLET = 'Pallet'
}

export enum FeeType {
  DAILY_RENTAL = 'Daily Rental (Supermarket)',
  ISSUE_FEE = 'Issue Fee (QSR)'
}

export enum MovementCondition {
  CLEAN = 'Clean',
  DIRTY = 'Dirty',
  DAMAGED = 'Damaged'
}

export interface AssetMaster {
  id: string;
  name: string;
  type: AssetType;
  dimensions: string;
  material: string;
}

export interface FeeSchedule {
  id: string;
  asset_id: string;
  fee_type: FeeType;
  amount_zar: number;
  effective_from: string; // ISO Date
  effective_to: string | null; // NULL means currently active
}

export interface Location {
  id: string;
  name: string;
  type: LocationType;
}

export interface LogisticsUnit {
  id: string;
  truck_plate: string;
  driver_name: string;
}

export interface Batch {
  id: string;
  asset_id: string;
  quantity: number;
  current_location_id: string;
  created_at: string;
  status: 'Pending' | 'Success';
}

export interface BatchMovement {
  id: string;
  batch_id: string;
  from_location_id: string;
  to_location_id: string;
  logistics_id?: string;
  timestamp: string;
  condition: MovementCondition;
}

export interface ThaanSlip {
  id: string;
  batch_id: string;
  doc_url: string;
  is_signed: boolean;
  signed_at: string | null;
}

export interface Claim {
  id: string;
  batch_id: string;
  type: 'Damaged' | 'Dirty';
  amount_claimed_zar: number;
  status: 'Pending' | 'Received';
  created_at: string;
}

import { AssetMaster, AssetType, FeeSchedule, FeeType, Location, LocationType, LogisticsUnit, Batch, BatchMovement, MovementCondition, ThaanSlip, Claim } from './types';

export const MOCK_ASSETS: AssetMaster[] = [
  { id: 'A1', name: 'Standard Milk Crate', type: AssetType.CRATE, dimensions: '33x33x28cm', material: 'HDPE' },
  { id: 'A2', name: 'Euro Pallet', type: AssetType.PALLET, dimensions: '800x1200mm', material: 'Pine' },
  { id: 'A3', name: 'Plastic Bread Crate', type: AssetType.CRATE, dimensions: '60x40x15cm', material: 'PP' },
];

export const MOCK_LOCATIONS: Location[] = [
  { id: 'L1', name: 'JHB Main Depot', type: LocationType.CRATES_DEPT },
  { id: 'L2', name: 'Cape Town Cold Storage', type: LocationType.WAREHOUSE },
  { id: 'L3', name: 'Pick n Pay Durban', type: LocationType.AT_CUSTOMER },
  { id: 'L4', name: 'Truck ZN-44-BB', type: LocationType.IN_TRANSIT },
  { id: 'L5', name: 'Supplier Returns Yard', type: LocationType.RETURNING },
];

export const MOCK_FEES: FeeSchedule[] = [
  { id: 'F1', asset_id: 'A1', fee_type: FeeType.DAILY_RENTAL, amount_zar: 5.00, effective_from: '2025-01-01', effective_to: '2025-12-31' },
  { id: 'F2', asset_id: 'A1', fee_type: FeeType.DAILY_RENTAL, amount_zar: 5.50, effective_from: '2026-01-01', effective_to: null },
  { id: 'F3', asset_id: 'A2', fee_type: FeeType.ISSUE_FEE, amount_zar: 120.00, effective_from: '2025-01-01', effective_to: null },
];

export const MOCK_LOGISTICS: LogisticsUnit[] = [
  { id: 'LOG1', truck_plate: 'CA 123-456', driver_name: 'Sipho Ndlovu' },
  { id: 'LOG2', truck_plate: 'GP 999-001', driver_name: 'Pieter Marais' },
];

export const MOCK_BATCHES: Batch[] = [
  { id: 'B-001', asset_id: 'A1', quantity: 500, current_location_id: 'L3', created_at: '2025-05-12T08:30:00Z', status: 'Success' },
  { id: 'B-002', asset_id: 'A2', quantity: 24, current_location_id: 'L4', created_at: '2026-02-15T14:20:00Z', status: 'Pending' },
];

export const MOCK_MOVEMENTS: BatchMovement[] = [
  { id: 'M1', batch_id: 'B-001', from_location_id: 'L1', to_location_id: 'L3', timestamp: '2025-05-12T08:30:00Z', condition: MovementCondition.CLEAN },
  { id: 'M2', batch_id: 'B-002', from_location_id: 'L1', to_location_id: 'L4', timestamp: '2026-02-15T14:20:00Z', condition: MovementCondition.CLEAN, logistics_id: 'LOG1' },
];

export const MOCK_THAANS: ThaanSlip[] = [
  { id: 'T1', batch_id: 'B-001', doc_url: 'https://picsum.photos/seed/thaan1/400/600', is_signed: true, signed_at: '2025-05-12T09:15:00Z' },
];

export const MOCK_CLAIMS: Claim[] = [
  { id: 'C1', batch_id: 'B-001', type: 'Damaged', amount_claimed_zar: 250.00, status: 'Pending', created_at: '2025-05-13T10:00:00Z' },
];

import React, { useState } from 'react';
import { 
  Package, 
  MapPin, 
  Truck, 
  History, 
  FileCheck, 
  AlertTriangle, 
  Database,
  Search,
  ChevronRight,
  TrendingUp,
  LayoutDashboard
} from 'lucide-react';
import DashboardView from './components/DashboardView';
import SchemaView from './components/SchemaView';
import BatchTracker from './components/BatchTracker';
import AssetList from './components/AssetList';
import ClaimsManager from './components/ClaimsManager';

enum NavItem {
  DASHBOARD = 'dashboard',
  ASSETS = 'assets',
  TRACKER = 'tracker',
  CLAIMS = 'claims',
  SCHEMA = 'schema'
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<NavItem>(NavItem.DASHBOARD);

  const renderContent = () => {
    switch (activeTab) {
      case NavItem.DASHBOARD: return <DashboardView />;
      case NavItem.ASSETS: return <AssetList />;
      case NavItem.TRACKER: return <BatchTracker />;
      case NavItem.CLAIMS: return <ClaimsManager />;
      case NavItem.SCHEMA: return <SchemaView />;
      default: return <DashboardView />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col fixed h-full z-10">
        <div className="p-6 flex items-center gap-3">
          <div className="bg-emerald-500 p-2 rounded-lg">
            <Package className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="font-bold text-lg leading-tight">CrateTrack</h1>
            <p className="text-xs text-slate-400">Logistics SA</p>
          </div>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          <SidebarButton 
            active={activeTab === NavItem.DASHBOARD} 
            onClick={() => setActiveTab(NavItem.DASHBOARD)}
            icon={<LayoutDashboard size={20} />}
            label="Dashboard" 
          />
          <SidebarButton 
            active={activeTab === NavItem.ASSETS} 
            onClick={() => setActiveTab(NavItem.ASSETS)}
            icon={<Database size={20} />}
            label="Asset Master" 
          />
          <SidebarButton 
            active={activeTab === NavItem.TRACKER} 
            onClick={() => setActiveTab(NavItem.TRACKER)}
            icon={<History size={20} />}
            label="Batch Movements" 
          />
          <SidebarButton 
            active={activeTab === NavItem.CLAIMS} 
            onClick={() => setActiveTab(NavItem.CLAIMS)}
            icon={<AlertTriangle size={20} />}
            label="Claims Management" 
          />
          <div className="pt-4 mt-4 border-t border-slate-800">
            <SidebarButton 
              active={activeTab === NavItem.SCHEMA} 
              onClick={() => setActiveTab(NavItem.SCHEMA)}
              icon={<Search size={20} />}
              label="System Design" 
            />
          </div>
        </nav>

        <div className="p-6 bg-slate-800">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-8 h-8 rounded-full bg-slate-600 flex items-center justify-center text-xs font-bold">
              JD
            </div>
            <div className="overflow-hidden">
              <p className="text-sm font-medium truncate">John Dlamini</p>
              <p className="text-xs text-slate-400">Fleet Manager</p>
            </div>
          </div>
          <button className="w-full py-2 px-3 text-xs bg-slate-700 hover:bg-slate-600 rounded transition-colors">
            Log Out
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="ml-64 flex-1 flex flex-col min-h-screen">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 sticky top-0 z-20">
          <h2 className="font-semibold text-lg text-slate-800 capitalize">
            {activeTab.replace('-', ' ')}
          </h2>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-xs font-medium text-slate-500">System Time (SAST)</p>
              <p className="text-sm font-bold">{new Date().toLocaleTimeString('en-ZA')}</p>
            </div>
            <div className="h-8 w-px bg-slate-200" />
            <button className="p-2 text-slate-400 hover:text-emerald-500 transition-colors">
              <FileCheck size={20} />
            </button>
          </div>
        </header>

        <div className="p-8">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

interface SidebarButtonProps {
  active: boolean;
  onClick: () => void;
  icon: React.ReactNode;
  label: string;
}

const SidebarButton: React.FC<SidebarButtonProps> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 ${
      active 
        ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/20' 
        : 'text-slate-400 hover:bg-slate-800 hover:text-white'
    }`}
  >
    {icon}
    <span className="font-medium text-sm">{label}</span>
    {active && <ChevronRight className="ml-auto" size={14} />}
  </button>
);

export default App;

import React from 'react';
import { Truck, Package, AlertTriangle, TrendingUp, ArrowUpRight, ArrowDownRight } from 'lucide-react';
import { MOCK_BATCHES, MOCK_CLAIMS } from '../constants';

const DashboardView: React.FC = () => {
  return (
    <div className="space-y-8">
      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          label="Active Batches" 
          value={MOCK_BATCHES.length.toString()} 
          trend="+2.5%" 
          trendUp={true} 
          icon={<Package className="text-blue-500" />} 
        />
        <StatCard 
          label="In Transit" 
          value="12" 
          trend="-4%" 
          trendUp={false} 
          icon={<Truck className="text-amber-500" />} 
        />
        <StatCard 
          label="Pending Claims" 
          value={MOCK_CLAIMS.filter(c => c.status === 'Pending').length.toString()} 
          trend="+1" 
          trendUp={true} 
          icon={<AlertTriangle className="text-rose-500" />} 
        />
        <StatCard 
          label="Avg Turnaround" 
          value="4.2 Days" 
          trend="0.5%" 
          trendUp={true} 
          icon={<TrendingUp className="text-emerald-500" />} 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Recent Movements */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-bold text-slate-800">Live Batch Stream</h3>
            <button className="text-xs text-emerald-600 font-bold hover:underline">View All</button>
          </div>
          <div className="divide-y divide-slate-50">
            {[1, 2, 3, 4].map((i) => (
              <div key={i} className="px-6 py-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-4">
                  <div className={`p-2 rounded-lg ${i % 2 === 0 ? 'bg-amber-100 text-amber-600' : 'bg-emerald-100 text-emerald-600'}`}>
                    {i % 2 === 0 ? <Truck size={20} /> : <Package size={20} />}
                  </div>
                  <div>
                    <p className="font-medium text-slate-800">Batch #B-0{10+i}</p>
                    <p className="text-xs text-slate-500">Depot A &rarr; Pick n Pay Sandton</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-sm font-bold text-slate-800">R { (2500 * i).toLocaleString() }</p>
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Estimated Fee</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Status Breakdown */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
          <h3 className="font-bold text-slate-800 mb-6">Asset Health</h3>
          <div className="space-y-6">
            <HealthBar label="Clean" percentage={85} color="bg-emerald-500" />
            <HealthBar label="Dirty" percentage={10} color="bg-amber-500" />
            <HealthBar label="Damaged" percentage={5} color="bg-rose-500" />
          </div>
          <div className="mt-8 p-4 bg-slate-50 rounded-lg border border-slate-100">
            <p className="text-xs text-slate-500 leading-relaxed italic">
              "System maintenance scheduled for Sunday at 02:00 SAST. Please ensure all THAAN slips are uploaded by end of shift Saturday."
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string, value: string, trend: string, trendUp: boolean, icon: React.ReactNode }> = ({ label, value, trend, trendUp, icon }) => (
  <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 hover:border-emerald-200 transition-colors group">
    <div className="flex items-center justify-between mb-4">
      <div className="p-2 bg-slate-50 rounded-lg group-hover:bg-white transition-colors">
        {icon}
      </div>
      <div className={`flex items-center text-xs font-bold ${trendUp ? 'text-emerald-500' : 'text-rose-500'}`}>
        {trend} {trendUp ? <ArrowUpRight size={14} /> : <ArrowDownRight size={14} />}
      </div>
    </div>
    <div>
      <h4 className="text-sm font-medium text-slate-500">{label}</h4>
      <p className="text-2xl font-bold text-slate-800 mt-1">{value}</p>
    </div>
  </div>
);

const HealthBar: React.FC<{ label: string, percentage: number, color: string }> = ({ label, percentage, color }) => (
  <div>
    <div className="flex justify-between text-xs mb-2">
      <span className="font-bold text-slate-600 uppercase tracking-wide">{label}</span>
      <span className="text-slate-400">{percentage}%</span>
    </div>
    <div className="w-full h-2 bg-slate-100 rounded-full overflow-hidden">
      <div className={`h-full ${color}`} style={{ width: `${percentage}%` }} />
    </div>
  </div>
);

export default DashboardView;

import React, { useState } from 'react';
import { MOCK_BATCHES, MOCK_MOVEMENTS, MOCK_LOCATIONS, MOCK_LOGISTICS, MOCK_FEES, MOCK_ASSETS, MOCK_THAANS } from '../constants';
import { Package, Truck, Clock, MapPin, CheckCircle2, AlertCircle, FileText, Zap } from 'lucide-react';
import { FeeType } from '../types';

const BatchTracker: React.FC = () => {
  const [selectedBatchId, setSelectedBatchId] = useState(MOCK_BATCHES[0].id);

  const currentBatch = MOCK_BATCHES.find(b => b.id === selectedBatchId)!;
  const movements = MOCK_MOVEMENTS.filter(m => m.batch_id === selectedBatchId);
  const asset = MOCK_ASSETS.find(a => a.id === currentBatch.asset_id)!;
  const thaan = MOCK_THAANS.find(t => t.batch_id === selectedBatchId);

  // Fee Lookup Simulation
  const getFeeForBatch = () => {
    const fee = MOCK_FEES.find(f => 
      f.asset_id === currentBatch.asset_id &&
      new Date(currentBatch.created_at) >= new Date(f.effective_from) &&
      (!f.effective_to || new Date(currentBatch.created_at) <= new Date(f.effective_to))
    );
    return fee;
  };

  const applicableFee = getFeeForBatch();

  return (
    <div className="space-y-8">
      {/* Selection Header */}
      <div className="flex flex-wrap gap-4 items-center">
        {MOCK_BATCHES.map(b => (
          <button 
            key={b.id}
            onClick={() => setSelectedBatchId(b.id)}
            className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${
              selectedBatchId === b.id 
                ? 'bg-slate-900 text-white ring-4 ring-slate-200' 
                : 'bg-white border border-slate-200 text-slate-500 hover:bg-slate-50'
            }`}
          >
            {b.id} ({b.status})
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Movement Timeline */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-xl border border-slate-200 p-8 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-8 flex items-center gap-2">
              <History size={20} className="text-emerald-500" />
              Movement History
            </h3>

            <div className="relative pl-8 border-l-2 border-slate-100 space-y-12">
              {movements.map((mv, idx) => {
                const from = MOCK_LOCATIONS.find(l => l.id === mv.from_location_id);
                const to = MOCK_LOCATIONS.find(l => l.id === mv.to_location_id);
                const logs = mv.logistics_id ? MOCK_LOGISTICS.find(l => l.id === mv.logistics_id) : null;

                return (
                  <div key={mv.id} className="relative">
                    <div className="absolute -left-[41px] top-0 w-4 h-4 rounded-full bg-emerald-500 ring-4 ring-emerald-50" />
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                      <div>
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">
                          {new Date(mv.timestamp).toLocaleString('en-ZA')}
                        </p>
                        <h4 className="font-bold text-slate-800 text-lg mt-1">
                          {from?.name} &rarr; {to?.name}
                        </h4>
                        <div className="flex gap-2 mt-2">
                          <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-tight ${
                            mv.condition === 'Clean' ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'
                          }`}>
                            {mv.condition}
                          </span>
                          {logs && (
                            <span className="bg-blue-100 text-blue-700 px-2 py-0.5 rounded text-[10px] font-bold flex items-center gap-1">
                              <Truck size={10} /> {logs.truck_plate}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}

              {/* If successful, show closure point */}
              {currentBatch.status === 'Success' && (
                <div className="relative">
                  <div className="absolute -left-[41px] top-0 w-4 h-4 rounded-full bg-emerald-600 ring-4 ring-emerald-100 flex items-center justify-center">
                    <CheckCircle2 size={10} className="text-white" />
                  </div>
                  <div>
                    <h4 className="font-bold text-emerald-600">Finalized - Delivery Confirmed</h4>
                    <p className="text-sm text-slate-500">All liability transferred to customer location.</p>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Right Column: Financials & Docs */}
        <div className="space-y-6">
          {/* Fee Breakdown */}
          <div className="bg-emerald-900 text-white rounded-xl p-6 shadow-xl relative overflow-hidden">
             <div className="absolute top-0 right-0 p-4 opacity-10">
               <Zap size={100} />
             </div>
             <h3 className="text-sm font-bold uppercase tracking-widest text-emerald-400 mb-4">Historical Fee Link</h3>
             <div className="space-y-4 relative z-10">
               <div className="flex justify-between border-b border-emerald-800 pb-2">
                 <span className="text-emerald-100 text-xs">Asset Type</span>
                 <span className="font-bold">{asset.name}</span>
               </div>
               <div className="flex justify-between border-b border-emerald-800 pb-2">
                 <span className="text-emerald-100 text-xs">Batch Date</span>
                 <span className="font-bold">{new Date(currentBatch.created_at).toLocaleDateString()}</span>
               </div>
               <div className="flex justify-between items-end">
                 <div>
                    <p className="text-[10px] text-emerald-400 font-bold uppercase">Rate (v{applicableFee?.id})</p>
                    <p className="text-2xl font-bold">R {applicableFee?.amount_zar.toFixed(2)}</p>
                 </div>
                 <div className="text-right">
                    <p className="text-[10px] text-emerald-400 font-bold uppercase">Line Total</p>
                    <p className="text-2xl font-bold">R {(currentBatch.quantity * (applicableFee?.amount_zar || 0)).toLocaleString()}</p>
                 </div>
               </div>
               <p className="text-[10px] text-emerald-500 italic">
                 Applied based on Fee Schedule active from {applicableFee?.effective_from}
               </p>
             </div>
          </div>

          {/* Document Section */}
          <div className="bg-white rounded-xl border border-slate-200 p-6 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <FileText size={18} className="text-slate-400" />
              THAAN Document
            </h3>
            {thaan ? (
              <div className="space-y-4">
                <div className="aspect-[4/5] bg-slate-100 rounded-lg border-2 border-dashed border-slate-200 overflow-hidden relative group">
                  <img src={thaan.doc_url} alt="THAAN Slip" className="w-full h-full object-cover group-hover:scale-105 transition-transform" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <button className="bg-white text-slate-900 px-4 py-2 rounded-lg text-xs font-bold shadow-lg">View Full Resolution</button>
                  </div>
                </div>
                <div className={`p-3 rounded-lg flex items-center gap-3 ${thaan.is_signed ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-amber-50 text-amber-700 border border-amber-100'}`}>
                  {thaan.is_signed ? <CheckCircle2 size={18} /> : <AlertCircle size={18} />}
                  <span className="text-xs font-bold">{thaan.is_signed ? `Signed on ${new Date(thaan.signed_at!).toLocaleDateString()}` : 'Signature Pending'}</span>
                </div>
              </div>
            ) : (
              <div className="py-8 text-center bg-slate-50 rounded-lg border-2 border-dashed border-slate-200">
                <p className="text-xs text-slate-400 font-medium">No document uploaded yet</p>
                <button className="mt-2 text-xs text-emerald-600 font-bold hover:underline">Upload Slip</button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default BatchTracker;

