const SchemaView: React.FC = () => {
  const [activeView, setActiveView] = useState<'visual' | 'sql' | 'python' | 'simulator'>('visual');

  // Simulator State
  const [simCondition, setSimCondition] = useState<'Clean' | 'Damaged'>('Clean');
  const [simThaan, setSimThaan] = useState(false);
  const [simClaimReceived, setSimClaimReceived] = useState(false);
  const [simDays, setSimDays] = useState(10);
  const [simAssetType, setSimAssetType] = useState<'Supermarket' | 'QSR'>('Supermarket');

  const entities = [
    { name: 'AssetMaster', fields: ['id', 'name', 'type', 'dimensions', 'material'] },
    { name: 'FeeSchedule', fields: ['id', 'asset_id (FK)', 'fee_type', 'amount_zar', 'effective_from', 'effective_to'] },
    { name: 'Locations', fields: ['id', 'name', 'type'] },
    { name: 'LogisticsUnits', fields: ['id', 'truck_plate', 'driver_name'] },
    { name: 'Batches', fields: ['id', 'asset_id (FK)', 'quantity', 'current_location_id (FK)', 'created_at', 'status'] },
    { name: 'BatchMovements', fields: ['id', 'batch_id (FK)', 'from_location_id (FK)', 'to_location_id (FK)', 'logistics_id (FK)', 'timestamp', 'condition'] },
    { name: 'ThaanSlips', fields: ['id', 'batch_id (FK)', 'doc_url', 'is_signed', 'signed_at'] },
    { name: 'Claims', fields: ['id', 'batch_id (FK)', 'type', 'amount_claimed_zar', 'status', 'created_at', 'received_at'] },
  ];

  const calculateSimLiability = () => {
    let base = simAssetType === 'Supermarket' ? 5.00 : 120.00; // Mock historical rates
    let quantity = 100;

    if (simAssetType === 'Supermarket') {
      // Rental continues if damaged until claim received
      let activeDays = simDays;
      if (simCondition === 'Clean' && simThaan) {
        activeDays = Math.min(simDays, 5); // Stopped early by THAAN
      } else if (simCondition === 'Damaged' && simClaimReceived) {
        activeDays = Math.min(simDays, 8); // Stopped by Claim settlement
      }
      return activeDays * base * quantity;
    } else {
      // QSR Logic
      let fee = base * quantity;
      if (simThaan) fee = 0; // Credit back
      return fee;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between overflow-x-auto pb-2">
        <div className="flex bg-slate-200 p-1 rounded-lg">
          <TabButton active={activeView === 'visual'} onClick={() => setActiveView('visual')} label="Visual Diagram" />
          <TabButton active={activeView === 'sql'} onClick={() => setActiveView('sql')} label="SQL Logic" />
          <TabButton active={activeView === 'python'} onClick={() => setActiveView('python')} label="Python Logic" />
          <TabButton active={activeView === 'simulator'} onClick={() => setActiveView('simulator')} label="Accrual Simulator" />
        </div>
      </div>

      {activeView === 'visual' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 p-6 bg-slate-900 rounded-2xl border border-slate-800 overflow-auto max-h-[700px]">
          {entities.map(entity => (
            <div key={entity.name} className="bg-slate-800 border border-slate-700 rounded-lg overflow-hidden h-fit">
              <div className="px-4 py-2 bg-slate-700 border-b border-slate-600 flex items-center gap-2">
                <TableIcon size={14} className="text-emerald-400" />
                <span className="text-xs font-bold text-white tracking-wider uppercase">{entity.name}</span>
              </div>
              <div className="p-3 space-y-1">
                {entity.fields.map(field => (
                  <div key={field} className="text-xs text-slate-400 flex items-center gap-2 py-1 border-b border-slate-700/50 last:border-0">
                    <div className="w-1.5 h-1.5 rounded-full bg-slate-600" />
                    {field}
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      {activeView === 'sql' && (
        <div className="space-y-6">
          <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-sm overflow-x-auto">
            <div className="text-emerald-400 mb-4 flex items-center gap-2">
              <Code size={18} />
              <span>Historical Fee Linking Query</span>
            </div>
            <pre className="text-slate-300 leading-relaxed">
{`-- Find the specific historical rate active on the day the batch was received
SELECT 
    b.id as batch_id,
    fs.amount_zar as historical_rate,
    (b.quantity * fs.amount_zar) as liability_base
FROM Batches b
JOIN FeeSchedule fs ON b.asset_id = fs.asset_id
WHERE b.id = 'B-001'
  AND b.created_at BETWEEN fs.effective_from AND COALESCE(fs.effective_to, '9999-12-31');`}
            </pre>
          </div>
        </div>
      )}

      {activeView === 'python' && (
        <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-sm overflow-x-auto">
          <div className="text-blue-400 mb-4 flex items-center gap-2">
            <Calculator size={18} />
            <span>Accrued Liability Logic (Python)</span>
          </div>
          <pre className="text-slate-300 leading-relaxed">
{`def calculate_accrued_liability(batch_id, current_ts):
    # 1. Historical Fee Lookup (Crucial: uses batch receipt date)
    batch = db.get_batch(batch_id)
    fee = db.get_historical_fee(batch.asset_id, batch.receipt_date)

    # 2. Path Analysis (Penalty Logic)
    path = db.get_movement_history(batch_id)
    if skipped_customer(path):
        return batch.qty * fee.issue_penalty # Flat Penalty

    # 3. Supermarket Logic (Daily Rental)
    if fee.type == "Daily Rental":
        thaan = db.get_signed_thaan(batch_id)
        claim = db.get_accepted_claim(batch_id)

        # Condition Logic: Rental timer follows condition
        if batch.condition == "Clean" and thaan:
            end_date = thaan.signed_at
        elif batch.condition in ["Dirty", "Damaged"]:
            # Rental continues until Supplier accepts credit claim
            end_date = claim.received_at if claim else current_ts
        else:
            end_date = current_ts

        days = (end_date - batch.receipt_date).days
        return days * fee.amount * batch.qty

    # 4. QSR Logic (Issue Fee + Credit)
    if fee.type == "Issue Fee":
        accrued = fee.amount * batch.qty
        thaan = db.get_signed_thaan(batch_id)
        if thaan: accrued = 0 # Credit back on successful transfer
        return accrued`}
          </pre>
        </div>
      )}

      {activeView === 'simulator' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm space-y-6">
            <h3 className="font-bold text-slate-800 flex items-center gap-2">
              <ShieldCheck className="text-emerald-500" size={20} />
              Accrual Logic Simulator
            </h3>

            <div className="space-y-4">
              <label className="block">
                <span className="text-xs font-bold text-slate-500 uppercase">Logic Mode</span>
                <select 
                  className="w-full mt-1 border border-slate-200 rounded p-2 text-sm"
                  value={simAssetType}
                  onChange={(e) => setSimAssetType(e.target.value as any)}
                >
                  <option value="Supermarket">Supermarket (Daily Rental)</option>
                  <option value="QSR">QSR (Issue Fee)</option>
                </select>
              </label>

              <div className="flex gap-4">
                <button 
                  onClick={() => setSimCondition(simCondition === 'Clean' ? 'Damaged' : 'Clean')}
                  className={`flex-1 p-3 rounded-lg border-2 text-xs font-bold transition-all ${simCondition === 'Clean' ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-rose-500 bg-rose-50 text-rose-700'}`}
                >
                  Condition: {simCondition}
                </button>
                <button 
                  onClick={() => setSimThaan(!simThaan)}
                  className={`flex-1 p-3 rounded-lg border-2 text-xs font-bold transition-all ${simThaan ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-slate-200 bg-slate-50 text-slate-400'}`}
                >
                  Signed THAAN: {simThaan ? 'YES' : 'NO'}
                </button>
              </div>

              {simCondition === 'Damaged' && (
                <button 
                  onClick={() => setSimClaimReceived(!simClaimReceived)}
                  className={`w-full p-3 rounded-lg border-2 text-xs font-bold transition-all ${simClaimReceived ? 'border-amber-500 bg-amber-50 text-amber-700' : 'border-slate-200 bg-slate-50 text-slate-400'}`}
                >
                  Claim Settled: {simClaimReceived ? 'YES' : 'NO'}
                </button>
              )}

              <label className="block">
                <span className="text-xs font-bold text-slate-500 uppercase">Elapsed Days: {simDays}</span>
                <input 
                  type="range" min="1" max="30" value={simDays} 
                  onChange={(e) => setSimDays(parseInt(e.target.value))}
                  className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer mt-2"
                />
              </label>
            </div>
          </div>

          <div className="bg-slate-900 rounded-xl p-8 text-white flex flex-col justify-center items-center text-center">
            <Zap className="text-emerald-400 mb-4" size={48} />
            <h4 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-1">Calculated Accrued Liability</h4>
            <div className="text-5xl font-bold text-white mb-2">R {calculateSimLiability().toLocaleString()}</div>
            <div className="p-4 bg-slate-800 rounded-lg border border-slate-700 mt-6 max-w-xs">
              <p className="text-xs text-slate-400 leading-relaxed">
                {simAssetType === 'Supermarket' 
                  ? (simCondition === 'Damaged' && !simClaimReceived 
                      ? "Timer running! Damaged assets accrue fees until the claim is settled." 
                      : simThaan 
                        ? "Liability stopped. Valid THAAN signature confirmed." 
                        : "Accruing daily rental fees...")
                  : (simThaan ? "Fee credited. Crate successfully issued to customer." : "Issue fee applied. Credit pending THAAN upload.")}
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

