const DashboardView: React.FC = () => {
  // Logic to find stale batches (> 24h in transit)
  const now = new Date();
  const staleBatches = MOCK_BATCHES.filter(batch => {
    const loc = MOCK_LOCATIONS.find(l => l.id === batch.current_location_id);
    if (loc?.type !== LocationType.IN_TRANSIT) return false;

    const lastMovement = MOCK_MOVEMENTS
      .filter(m => m.batch_id === batch.id)
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())[0];

    if (!lastMovement) return false;

    const diffHours = (now.getTime() - new Date(lastMovement.timestamp).getTime()) / (1000 * 60 * 60);
    return diffHours > 24;
  });

  // Weekly Accrual Estimates
  const totalPallets = MOCK_BATCHES.reduce((acc, b) => b.asset_id === 'A2' ? acc + b.quantity : acc, 0);
  const estimatedUnbilledRental = 15420.50; // Mock calculation
  const pendingClaimsValue = MOCK_CLAIMS.filter(c => c.status === 'Pending').reduce((acc, c) => acc + c.amount_claimed_zar, 0);

  return (
    <div className="space-y-8">
      {/* Alerts Banner */}
      {staleBatches.length > 0 && (
