            </p>
            <div className="mt-2 flex gap-2">
              {staleBatches.map(b => (
                <span key={b.id} className="bg-rose-100 text-rose-700 px-2 py-0.5 rounded text-[10px] font-bold border border-rose-200 uppercase">
                  {b.id}
                </span>
              ))}
            </div>
          </div>
          <button className="text-xs font-bold text-rose-700 hover:underline">View Fleet</button>
