          trendUp={true} 
          icon={<Package className="text-blue-500" />} 
        />
        <StatCard 
          label="In Transit" 
          value={MOCK_BATCHES.filter(b => MOCK_LOCATIONS.find(l => l.id === b.current_location_id)?.type === LocationType.IN_TRANSIT).length.toString()} 
