import React, { useState } from 'react';
import { Truck, MapPin, ClipboardList, CheckCircle2, AlertTriangle, ArrowRight, User, Package, Zap } from 'lucide-react';
import { MOCK_BATCHES, MOCK_LOCATIONS, MOCK_LOGISTICS } from '../constants';
import { MovementCondition, LocationType } from '../types';

const LogisticsOps: React.FC = () => {
  const [formData, setFormData] = useState({
    batchId: MOCK_BATCHES[0].id,
    fromLoc: MOCK_LOCATIONS[0].id,
    toLoc: MOCK_LOCATIONS[1].id,
    logisticsId: MOCK_LOGISTICS[0].id,
    quantity: 100
  });

  const [conditionData, setConditionData] = useState({
    batchId: MOCK_BATCHES[0].id,
    condition: MovementCondition.CLEAN
  });

  const [notification, setNotification] = useState<{message: string, type: 'success' | 'alert'} | null>(null);

  const handleLogMovement = (e: React.FormEvent) => {
    e.preventDefault();
    setNotification({ 
      message: `Batch ${formData.batchId} successfully dispatched to ${MOCK_LOCATIONS.find(l => l.id === formData.toLoc)?.name}`, 
      type: 'success' 
    });
    setTimeout(() => setNotification(null), 3000);
  };

  const handleConditionUpdate = () => {
    let msg = `Condition for ${conditionData.batchId} updated to ${conditionData.condition}.`;
    if (conditionData.condition !== MovementCondition.CLEAN) {
      msg += ` Auto-generated Supplier Claim triggered.`;
    }
    setNotification({ message: msg, type: conditionData.condition === MovementCondition.CLEAN ? 'success' : 'alert' });
    setTimeout(() => setNotification(null), 5000);
  };

  return (
    <div className="space-y-8">
      {notification && (
        <div className={`fixed bottom-8 right-8 z-50 p-4 rounded-xl shadow-2xl flex items-center gap-3 animate-bounce max-w-md ${notification.type === 'success' ? 'bg-emerald-600 text-white' : 'bg-rose-600 text-white'}`}>
          {notification.type === 'success' ? <CheckCircle2 size={24} /> : <AlertTriangle size={24} />}
          <p className="text-sm font-bold">{notification.message}</p>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Log Movement Form */}
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="px-6 py-4 bg-slate-900 text-white flex items-center gap-2">
            <Truck size={18} className="text-emerald-400" />
            <h3 className="font-bold text-sm uppercase tracking-widest">Dispatch / Movement Log</h3>
          </div>
          <form onSubmit={handleLogMovement} className="p-8 space-y-6">
            <div className="grid grid-cols-2 gap-4">
              <label className="block space-y-1">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-tight">Select Batch</span>
                <select 
                  className="w-full border border-slate-200 rounded-lg p-3 text-sm focus:ring-2 focus:ring-emerald-500"
                  value={formData.batchId}
                  onChange={e => setFormData({...formData, batchId: e.target.value})}
                >
                  {MOCK_BATCHES.map(b => <option key={b.id} value={b.id}>{b.id} ({b.quantity} Units)</option>)}
                </select>
              </label>
              <label className="block space-y-1">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-tight">Move Quantity</span>
                <input 
                  type="number" 
                  className="w-full border border-slate-200 rounded-lg p-3 text-sm focus:ring-2 focus:ring-emerald-500"
                  value={formData.quantity}
                  onChange={e => setFormData({...formData, quantity: parseInt(e.target.value)})}
                />
              </label>
            </div>

            <div className="flex items-center gap-4 bg-slate-50 p-4 rounded-xl border border-slate-100">
              <div className="flex-1 space-y-1">
                <span className="text-[10px] font-bold text-slate-400 uppercase">From</span>
                <div className="flex items-center gap-2 text-slate-700">
                  <MapPin size={14} />
                  <select 
                    className="bg-transparent text-sm font-bold outline-none border-0 p-0"
                    value={formData.fromLoc}
                    onChange={e => setFormData({...formData, fromLoc: e.target.value})}
                  >
                    {MOCK_LOCATIONS.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}
                  </select>
                </div>
              </div>
              <ArrowRight className="text-slate-300" />
              <div className="flex-1 space-y-1">
                <span className="text-[10px] font-bold text-slate-400 uppercase">To</span>
                <div className="flex items-center gap-2 text-slate-700">
                  <MapPin size={14} />
                  <select 
                    className="bg-transparent text-sm font-bold outline-none border-0 p-0"
                    value={formData.toLoc}
                    onChange={e => setFormData({...formData, toLoc: e.target.value})}
                  >
                    {MOCK_LOCATIONS.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}
                  </select>
                </div>
              </div>
            </div>

            <div className="space-y-4 pt-4 border-t border-slate-100">
              <h4 className="text-xs font-bold text-slate-400 uppercase flex items-center gap-2">
                <User size={14} /> Logistics Assignment
              </h4>
              <label className="block">
                <select 
                  className="w-full border border-slate-200 rounded-lg p-3 text-sm focus:ring-2 focus:ring-emerald-500"
                  value={formData.logisticsId}
                  onChange={e => setFormData({...formData, logisticsId: e.target.value})}
                >
                  {MOCK_LOGISTICS.map(l => <option key={l.id} value={l.id}>{l.truck_plate} - {l.driver_name}</option>)}
                </select>
              </label>
            </div>

            <button type="submit" className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-4 rounded-xl shadow-lg shadow-emerald-200 transition-all flex items-center justify-center gap-3">
              <Zap size={20} />
              CONFIRM DISPATCH
            </button>
          </form>
        </div>

        {/* Condition Capture Tool */}
        <div className="space-y-8">
          <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="px-6 py-4 bg-slate-900 text-white flex items-center gap-2">
              <ClipboardList size={18} className="text-amber-400" />
              <h3 className="font-bold text-sm uppercase tracking-widest">Return Condition Check</h3>
            </div>
            <div className="p-8 space-y-6">
              <p className="text-xs text-slate-500 leading-relaxed italic border-l-4 border-amber-200 pl-4 bg-amber-50 py-2">
                "Note: Flagging a batch as Dirty or Damaged will automatically freeze the rental timer and initiate a Supplier Claim entry for credit processing."
              </p>

              <label className="block space-y-2">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-tight">Select Return Batch</span>
                <select 
                  className="w-full border border-slate-200 rounded-lg p-3 text-sm focus:ring-2 focus:ring-amber-500"
                  value={conditionData.batchId}
                  onChange={e => setConditionData({...conditionData, batchId: e.target.value})}
                >
                  {MOCK_BATCHES.map(b => <option key={b.id} value={b.id}>{b.id}</option>)}
                </select>
              </label>

              <div className="space-y-3">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-tight">Flag Condition</span>
                <div className="grid grid-cols-3 gap-3">
                  {[MovementCondition.CLEAN, MovementCondition.DIRTY, MovementCondition.DAMAGED].map(cond => (
                    <button
                      key={cond}
                      onClick={() => setConditionData({...conditionData, condition: cond})}
                      className={`py-3 px-2 rounded-lg text-[10px] font-bold uppercase transition-all border-2 ${
                        conditionData.condition === cond 
                          ? (cond === 'Clean' ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'bg-rose-50 border-rose-500 text-rose-700')
                          : 'bg-white border-slate-100 text-slate-400'
                      }`}
                    >
                      {cond}
                    </button>
                  ))}
                </div>
              </div>

              <button 
                onClick={handleConditionUpdate}
                className="w-full py-4 border-2 border-slate-900 text-slate-900 font-bold rounded-xl hover:bg-slate-900 hover:text-white transition-all"
              >
                SUBMIT ASSESSMENT
              </button>
            </div>
          </div>

          <div className="bg-emerald-900 text-white p-6 rounded-xl shadow-xl">
             <div className="flex items-center gap-3 mb-4">
               <Package className="text-emerald-400" />
               <h4 className="font-bold">Fleet Stats Overview</h4>
             </div>
             <div className="grid grid-cols-2 gap-4">
               <div className="bg-emerald-800 p-3 rounded-lg">
                 <p className="text-[10px] text-emerald-300 uppercase font-bold tracking-widest">Available Crates</p>
                 <p className="text-xl font-bold">12,400</p>
               </div>
               <div className="bg-emerald-800 p-3 rounded-lg">
                 <p className="text-[10px] text-emerald-300 uppercase font-bold tracking-widest">In Service</p>
                 <p className="text-xl font-bold">45,910</p>
               </div>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LogisticsOps;

