      if (simCondition === 'Clean' && simThaan) activeDays = Math.min(simDays, 5);
      else if (simCondition === 'Damaged' && simClaimReceived) activeDays = Math.min(simDays, 8);
      return activeDays * base * quantity;
    } else {
      let fee = base * quantity;
      if (simThaan) fee = 0;
      return fee;
    }
  };

  return (
