      {activeView === 'postgres' && (
        <div className="space-y-6">
          <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-sm overflow-x-auto">
            <div className="text-emerald-400 mb-4 flex items-center gap-2">
              <Code size={18} />
              <span>Credit & View Logic</span>
            </div>
            <pre className="text-slate-300 leading-relaxed">
{`-- 1. Net Payable View
CREATE OR REPLACE VIEW vw_net_payable_per_supplier AS
WITH Liability AS (
    SELECT 
        b.supplier_id, 
        SUM(b.quantity * fs.amount_zar * (CURRENT_DATE - b.created_at)) as total_accrued
    FROM Batches b
    JOIN FeeSchedule fs ON b.asset_id = fs.asset_id
    WHERE b.status != 'Settled'
    GROUP BY b.supplier_id
),
Credits AS (
    SELECT 
        b.supplier_id, 
        SUM(sc.amount_zar) as total_credits
    FROM SupplierCredits sc
    JOIN Claims c ON sc.claim_id = c.id
    JOIN Batches b ON c.batch_id = b.id
    GROUP BY b.supplier_id
)
SELECT 
    l.supplier_id,
    COALESCE(l.total_accrued, 0) as raw_liability,
    COALESCE(c.total_credits, 0) as approved_credits,
    (COALESCE(l.total_accrued, 0) - COALESCE(c.total_credits, 0)) as net_payable_zar
FROM Liability l
LEFT JOIN Credits c ON l.supplier_id = c.supplier_id;

-- 2. Audit Trail Trigger
CREATE OR REPLACE FUNCTION log_claim_status_change()
RETURNS TRIGGER AS $$
BEGIN
    IF OLD.status IS DISTINCT FROM NEW.status THEN
        INSERT INTO ClaimAudit (claim_id, status_from, status_to, updated_by, timestamp)
        VALUES (NEW.id, OLD.status, NEW.status, CURRENT_USER, NOW());
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- 3. Acceptance Credit Calculation
-- TRIGGERED on Claims.status -> 'Accepted'
-- Calculation: RentalRate * Days(LodgedDate to AcceptanceDate)`}
            </pre>
          </div>
        </div>
      )}

      {activeView === 'python' && (
        <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-sm overflow-x-auto">
          <div className="text-blue-400 mb-4 flex items-center gap-2">
            <Calculator size={18} />
            <span>Accrued Liability Logic</span>
          </div>
          <pre className="text-slate-300 leading-relaxed">
{`def calculate_accrued_liability(batch_id, current_ts):
    batch = db.get_batch(batch_id)
    fee = db.get_historical_fee(batch.asset_id, batch.receipt_date)

    # Supermarket Logic
    if fee.type == "Daily Rental":
        thaan = db.get_signed_thaan(batch_id)
        claim = db.get_accepted_claim(batch_id)

        # Disputed Timer Rule:
        # Fee accrues during damage discovery until 'Accepted'
        if batch.condition in ["Dirty", "Damaged"] and not claim:
            end_date = current_ts # Still accruing liability
        elif claim:
            # Liability stopped once supplier accepts (Credit logic handles refund)
            end_date = claim.accepted_at 
        elif thaan:
            end_date = thaan.signed_at
        else:
            end_date = current_ts

        return (end_date - batch.receipt_date).days * fee.amount * batch.qty`}
