                {simAssetType === 'Supermarket' 
                  ? (simCondition === 'Damaged' && !simClaimReceived 
                      ? "Disputed Timer: Still accruing rental fees until Supplier officially accepts responsibility." 
                      : simThaan 
                        ? "Liability stopped. Transfer successful." 
                        : "Accruing daily rental fees...")
                  : (simThaan ? "Fee credited." : "Issue fee applied.")}
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

