            <div className="text-emerald-400 flex items-center gap-2">
              <Database size={18} />
              <span>POSTGRES INSERT LOGIC (Movement Logger)</span>
            </div>
            <pre className="text-slate-300 leading-relaxed">
{`-- Record the transfer
INSERT INTO BatchMovements (
  batch_id, 
  from_location_id, 
  to_location_id, 
  logistics_id, 
  timestamp, 
  condition
) VALUES (
  'B-004', 
  'L1', -- JHB Depot
  'L3', -- At Customer
  'LOG1', 
  CURRENT_TIMESTAMP, 
  'Clean'
);

-- Link THAAN image to batch
-- Triggered by POST /upload-thaan
INSERT INTO ThaanSlips (
  batch_id, 
  thaan_blob_url, 
  is_signed, 
  signed_at
) VALUES (
  'B-004', 
  'https://s3.aws.com/thaan-slips/B-004_pod.jpg', 
  TRUE, 
  CURRENT_TIMESTAMP
);

-- Truck Load Real-time Query
-- Used by GET /truck-load/{license_plate}
CREATE OR REPLACE VIEW vw_truck_inventory AS
SELECT 
  l.truck_plate, 
  l.driver_name, 
  m.batch_id, 
  m.to_location_id,
  b.quantity,
  a.name as asset_name
FROM BatchMovements m
JOIN LogisticsUnits l ON m.logistics_id = l.id
JOIN Batches b ON m.batch_id = b.id
JOIN AssetMaster a ON b.asset_id = a.id
WHERE m.to_location_id IN (
  SELECT id FROM Locations WHERE type = 'In Transit'
)
AND m.timestamp = (
