export enum LocationType {
  CRATES_DEPT = 'Crates Dept',
  WAREHOUSE = 'Warehouse',
  COLD_STORAGE = 'Cold Storage',
  AT_CUSTOMER = 'At Customer',
  IN_TRANSIT = 'In Transit',
  RETURNING = 'Returning to Supplier'
}

export enum LocationCategory {
  HOME = 'Home',
  EXTERNAL = 'External'
}

export enum AssetType {
  CRATE = 'Crate',
  PALLET = 'Pallet'
}

export enum FeeType {
  DAILY_RENTAL = 'Daily Rental (Supermarket)',
  ISSUE_FEE = 'Issue Fee (QSR)'
}

export enum MovementCondition {
  CLEAN = 'Clean',
  DIRTY = 'Dirty',
  DAMAGED = 'Damaged'
}

export type ClaimStatus = 'Lodged' | 'Under Assessment' | 'Returned for Assessment' | 'Accepted' | 'Rejected';

export interface User {
  id: string;
  name: string;
  role: string;
  branch_id: string;
}

export interface AssetMaster {
  id: string;
  name: string;
  type: AssetType;
  dimensions: string;
  material: string;
}

export interface FeeSchedule {
  id: string;
  asset_id: string;
  fee_type: FeeType;
  amount_zar: number;
  effective_from: string; // ISO Date
  effective_to: string | null; // NULL means currently active
}

export interface Location {
  id: string;
