SELECT 
    loc.name AS location_name,
    loc.type AS location_type,
    asset.name AS asset_type,
    SUM(b.quantity) AS total_quantity,
    -- Accrual Logic: 
    -- rental_rate * qty * days_in_possession
    SUM(
        fs.amount_zar * b.quantity * 
        (EXTRACT(DAY FROM (NOW() - b.created_at)))
    ) AS total_accrued_cost
FROM Locations loc
JOIN Batches b ON loc.id = b.current_location_id
JOIN AssetMaster asset ON b.asset_id = asset.id
JOIN FeeSchedule fs ON asset.id = fs.asset_id
WHERE fs.effective_to IS NULL -- Active Rate
GROUP BY loc.name, loc.type, asset.name
ORDER BY total_accrued_cost DESC;

-- Multiple Home Locations Hierarchy
ALTER TABLE Locations 
ADD COLUMN category VARCHAR(20) 
CHECK (category IN ('Home', 'External'));

-- Multi-User Capture Logic
-- Movements must record WHO captured the site-entry
