const calculateBatchCost = (batch: any) => {
  const fee = MOCK_FEES.find(f => f.asset_id === batch.asset_id && f.effective_to === null);
  if (!fee) return 0;

  if (fee.fee_type.includes('Daily Rental')) {
    return batch.quantity * fee.amount_zar * batch.ageDays;
  } else {
    return batch.quantity * fee.amount_zar;
  }
};

