const FinancialReport: React.FC = () => {
  // 1. Active Liabilities: Total daily rental fees for Supermarket crates in possession
  const activeLiabilities = MOCK_BATCHES.reduce((total, batch) => {
    const loc = MOCK_LOCATIONS.find(l => l.id === batch.current_location_id);
    const fee = MOCK_FEES.find(f => f.asset_id === batch.asset_id && f.fee_type.includes('Daily Rental') && f.effective_to === null);

    if (fee && loc && loc.type !== LocationType.AT_CUSTOMER && loc.type !== LocationType.RETURNING) {
      const ageDays = Math.floor((Date.now() - new Date(batch.created_at).getTime()) / (1000 * 60 * 60 * 24));
      return total + (batch.quantity * fee.amount_zar * ageDays);
    }
    return total;
  }, 0);

  // 2. Uncredited Issue Fees: QSR crates without signed THAAN
  const uncreditedIssueFees = MOCK_BATCHES.reduce((total, batch) => {
    const fee = MOCK_FEES.find(f => f.asset_id === batch.asset_id && f.fee_type.includes('Issue Fee') && f.effective_to === null);
    const thaan = MOCK_THAANS.find(t => t.batch_id === batch.id && t.is_signed);

    if (fee && !thaan) {
      return total + (batch.quantity * fee.amount_zar);
    }
    return total;
  }, 0);

  // 3. Pending Claims Value
  const pendingClaimsValue = MOCK_CLAIMS
    .filter(c => c.status === 'Under Assessment')
    .reduce((total, c) => total + c.amount_claimed_zar, 0);

  // 4. Penalty Exposure (Mocked logic for QSR returned without THAAN)
  const penaltyExposure = 12400.00; 

