              <AgingBar label="60 Days" count={agingStats['60d']} color="bg-orange-500" total={MOCK_BATCHES.length} />
              <AgingBar label="90 Days+" count={agingStats['90d+']} color="bg-rose-600" total={MOCK_BATCHES.length} />
            </div>

            <div className="overflow-x-auto">
