          <div className="flex items-center gap-3">
            <CheckCircle2 className="text-emerald-500" size={20} />
            <p className="text-sm font-bold text-emerald-800">{successMsg}</p>
          </div>
          <button onClick={() => setSuccessMsg(null)} className="text-emerald-400 hover:text-emerald-600 transition-colors">
            <XCircle size={18} />
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Form Column */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="px-6 py-4 bg-slate-900 text-white flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Skull size={18} className="text-rose-400" />
                <h3 className="font-bold text-sm uppercase tracking-widest">Asset Loss Report</h3>
              </div>
              <span className="text-[10px] font-bold text-slate-400 uppercase">Write-Off Mode</span>
            </div>

            <form onSubmit={handleRecordLoss} className="p-8 space-y-8">
              <div className="space-y-4">
                <label className="block space-y-2">
                  <span className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                    <Search size={14} /> Select Batch for Investigation
                  </span>
                  <select 
                    className="w-full border border-slate-200 rounded-xl p-4 text-sm focus:ring-2 focus:ring-rose-500 bg-slate-50 outline-none"
                    value={selectedBatchId}
                    onChange={e => setSelectedBatchId(e.target.value)}
                  >
                    <option value="">-- Choose a Batch --</option>
                    {MOCK_BATCHES.filter(b => b.status !== 'Lost').map(b => (
                      <option key={b.id} value={b.id}>
                        {b.id} ({b.quantity} {MOCK_ASSETS.find(a => a.id === b.asset_id)?.name})
                      </option>
                    ))}
                  </select>
                </label>

                {selectedBatchId && (
                  <div className="grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-bottom duration-300">
                    <label className="block space-y-2">
                      <span className="text-[10px] font-bold text-slate-400 uppercase">Quantity Lost</span>
                      <input 
                        type="number" 
                        max={selectedBatch?.quantity}
                        min={1}
                        className="w-full border border-slate-200 rounded-xl p-4 text-sm bg-white"
                        value={lostQty}
                        onChange={e => setLostQty(parseInt(e.target.value) || 0)}
                      />
                    </label>
                    <div className="flex flex-col justify-end pb-1">
                      <p className="text-[10px] text-slate-400 italic">Remaining in Batch: {Math.max(0, (selectedBatch?.quantity || 0) - lostQty)}</p>
                    </div>
                  </div>
                )}
              </div>

              {lastKnown && (
                <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100 space-y-6 animate-in zoom-in-95 duration-300">
                  <h4 className="text-xs font-bold text-slate-800 uppercase flex items-center gap-2 border-b border-slate-200 pb-2">
                    <Info size={14} className="text-blue-500" /> Automatic Last Known Discovery
                  </h4>

                  <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1">
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Location</p>
                      <div className="flex items-center gap-2 text-sm font-bold text-slate-700">
                        <MapPin size={14} className="text-rose-500" /> {lastKnown.location}
                      </div>
                      {lastKnown.customerName && (
                        <p className="text-[10px] text-emerald-600 font-bold uppercase mt-1">Found at Customer site</p>
                      )}
                    </div>

                    <div className="space-y-1">
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Logistics</p>
                      <div className="flex items-center gap-2 text-sm font-bold text-slate-700">
                        <Truck size={14} className="text-slate-400" /> {lastKnown.truck || 'None'} 
                      </div>
                      <p className="text-[10px] text-slate-500 font-medium">Driver: {lastKnown.driver || 'N/A'}</p>
                    </div>
                  </div>

                  {lastKnown.thaanUrl && (
                    <div className="p-4 bg-white rounded-xl border border-slate-200 flex items-center justify-between group cursor-pointer hover:border-blue-300 transition-colors">
                      <div className="flex items-center gap-3">
                        <FileText size={20} className="text-blue-500" />
                        <div>
                          <p className="text-xs font-bold text-slate-800">Linked THAAN Slip POD</p>
                          <p className="text-[10px] text-slate-400">Captured at last movement</p>
                        </div>
                      </div>
                      <button type="button" className="text-[10px] font-bold text-blue-600 uppercase hover:underline">View Proof</button>
                    </div>
                  )}
                </div>
              )}

              <label className="block space-y-2">
                <span className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                  Investigation Notes
                </span>
                <textarea 
                  className="w-full border border-slate-200 rounded-xl p-4 text-sm h-32 bg-slate-50 resize-none outline-none focus:ring-2 focus:ring-rose-500"
                  placeholder="Explain why this batch is being written off (e.g., Driver accident, site shrinkage, stolen in transit)..."
                  value={notes}
                  onChange={e => setNotes(e.target.value)}
                />
              </label>

              <button 
                type="submit" 
                disabled={!selectedBatchId || isProcessing}
                className={`w-full font-bold py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3 active:scale-[0.98] ${
                  !selectedBatchId 
                    ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                    : 'bg-rose-600 text-white hover:bg-rose-700 shadow-rose-200'
                }`}
              >
                {isProcessing ? (
                  <>
                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    Recording Write-Off...
                  </>
                ) : (
                  <>
                    <Skull size={20} className="text-rose-300" />
                    Record Official Asset Loss
                  </>
                )}
              </button>
            </form>
          </div>
        </div>

        {/* Sidebar Logic Panel */}
        <div className="space-y-6">
          <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm space-y-4">
             <h4 className="font-bold text-slate-800 text-xs uppercase tracking-widest flex items-center gap-2">
               <AlertTriangle className="text-amber-500" size={16} /> Possession Timer Guard
             </h4>
             <p className="text-xs text-slate-500 leading-relaxed">
               Recording a loss will immediately <strong>STOP</strong> all daily rental accruals for this specific batch quantity. 
             </p>
             <ul className="text-[10px] font-bold text-slate-400 space-y-2 uppercase list-disc pl-4">
               <li>Automatic POSSESSION TERMINATION</li>
               <li>FINANCIAL ACCRUAL CEASED</li>
               <li>ASSET DEPRECIATION TRIGGERED</li>
               <li>AUDIT LOG COMMITTED TO PG</li>
             </ul>
          </div>

          <div className="bg-slate-900 text-white p-8 rounded-2xl shadow-xl shadow-slate-200/50">
             <h4 className="font-bold mb-4 flex items-center gap-2 text-sm">
               <Database className="text-emerald-400" size={18} /> PG Trigger Logic
             </h4>
             <div className="space-y-4 font-mono text-[9px] text-slate-400">
               <p className="text-emerald-400">-- Automated Loss Discovery</p>
               <pre className="bg-slate-800 p-2 rounded leading-tight">
{`INSERT INTO asset_losses (
  batch_id, 
  last_known_location_id, 
  last_truck, 
  last_driver
) 
SELECT 
  id, 
  current_location_id,
  (SELECT truck_plate FROM LogisticsUnits WHERE id = m.logistics_id),
  (SELECT driver_name FROM LogisticsUnits WHERE id = m.logistics_id)
FROM Batches b
LEFT JOIN BatchMovements m ON b.id = m.batch_id
WHERE b.id = $1
ORDER BY m.timestamp DESC LIMIT 1;`}
               </pre>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

