                <TableIcon size={14} className="text-emerald-400" />
                <span className="text-xs font-bold text-white tracking-wider uppercase">{entity.name}</span>
              </div>
              <div className="p-3 space-y-1">
                {entity.fields.map(field => (
                  <div key={field} className="text-xs text-slate-400 flex items-center gap-2 py-1 border-b border-slate-700/50 last:border-0">
                    <div className="w-1.5 h-1.5 rounded-full bg-slate-600" />
                    {field}
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      {activeView === 'postgres' && (
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
          <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-xs overflow-x-auto space-y-8">
            <div className="text-rose-400 flex items-center gap-2">
              <Skull size={18} />
              <span>RECORD A LOSS (SQL INSERT SELECT)</span>
            </div>
            <pre className="text-slate-300 leading-relaxed">
{`-- Automated Investigation & Loss Commit
INSERT INTO AssetLosses (
    batch_id, 
    lost_qty, 
    last_known_loc_id, 
    last_driver, 
    last_truck, 
    thaan_url, 
    reported_by, 
    timestamp
)
SELECT 
    b.id, 
    $2, -- User-provided lost qty
    b.current_location_id,
    lu.driver_name,
    lu.truck_plate,
    ts.thaan_blob_url,
    $3, -- user_id
    CURRENT_TIMESTAMP
FROM Batches b
LEFT JOIN BatchMovements m ON b.id = m.batch_id
LEFT JOIN LogisticsUnits lu ON m.logistics_id = lu.id
LEFT JOIN ThaanSlips ts ON b.id = ts.batch_id
WHERE b.id = $1
ORDER BY m.timestamp DESC
LIMIT 1;

-- Inventory Reconciliation
UPDATE Batches 
SET quantity = quantity - $2,
    status = CASE WHEN (quantity - $2) <= 0 THEN 'Lost' ELSE status END
WHERE id = $1;

-- Stop Accruals Trigger
-- Rental engine should skip batches with status 'Lost'
-- OR batches where quantity is 0
`}
            </pre>
          </div>

          <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-xs overflow-x-auto space-y-8">
            <div className="text-amber-400 flex items-center gap-2">
              <Server size={18} />
              <span>PENALTY TRIGGER LOGIC</span>
            </div>
            <pre className="text-slate-300 leading-relaxed">
{`-- Identify QSR crates returned without THAAN Slip
-- Non-refundable issue fees detection
SELECT 
    m.batch_id, 
    m.timestamp, 
    b.quantity, 
    fs.amount_zar as loss_per_unit
FROM BatchMovements m
JOIN Batches b ON m.batch_id = b.id
JOIN AssetMaster a ON b.asset_id = a.id
JOIN FeeSchedule fs ON a.id = fs.asset_id
JOIN Locations l ON m.to_location_id = l.id
LEFT JOIN ThaanSlips ts ON m.batch_id = ts.batch_id
WHERE l.type = 'Returning to Supplier'
  AND fs.fee_type LIKE '%Issue Fee%'
  AND ts.id IS NULL;`}
            </pre>
            <div className="p-4 bg-rose-900/50 rounded border border-rose-800">
               <p className="text-[10px] text-rose-300 font-bold uppercase mb-2">Management Guardrail</p>
               <p className="text-xs text-rose-100 italic leading-relaxed">
                 Any QSR movement to "Supplier" without a validated customer THAAN slip results in immediate loss of the Issue Fee. This query flags compliance failures for payroll/driver penalties.
               </p>
            </div>
          </div>
        </div>
      )}

      {activeView === 'python' && (
        <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-sm overflow-x-auto">
          <div className="text-blue-400 mb-4 flex items-center gap-2">
            <Calculator size={18} />
            <span>Accrued Liability Logic</span>
          </div>
          <pre className="text-slate-300 leading-relaxed">
{`def calculate_accrued_liability(batch_id, current_ts):
    batch = db.get_batch(batch_id)
    fee = db.get_historical_fee(batch.asset_id, batch.receipt_date)

    # Supermarket Logic
    if fee.type == "Daily Rental":
        thaan = db.get_signed_thaan(batch_id)
        claim = db.get_accepted_claim(batch_id)

        # Disputed Timer Rule:
        # Fee accrues during damage discovery until 'Accepted'
        if batch.condition in ["Dirty", "Damaged"] and not claim:
            end_date = current_ts # Still accruing liability
        elif claim:
            # Liability stopped once supplier accepts (Credit logic handles refund)
            end_date = claim.accepted_at 
        elif thaan:
            end_date = thaan.signed_at
        else:
            end_date = current_ts

        return (end_date - batch.receipt_date).days * fee.amount * batch.qty`}
          </pre>
        </div>
      )}

      {activeView === 'simulator' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm space-y-6">
