                  className={`w-full p-3 rounded-lg border-2 text-xs font-bold transition-all ${simClaimReceived ? 'border-amber-500 bg-amber-50 text-amber-700' : 'border-slate-200 bg-slate-50 text-slate-400'}`}
                >
                  Supplier Accepted Claim: {simClaimReceived ? 'YES' : 'NO'}
                </button>
              )}

              <label className="block">
                <span className="text-xs font-bold text-slate-500 uppercase">Elapsed Days: {simDays}</span>
