            <Zap className="text-emerald-400 mb-4" size={48} />
            <h4 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-1">Calculated Accrued Liability</h4>
            <div className="text-5xl font-bold text-white mb-2">R {calculateSimLiability().toLocaleString()}</div>
