            <div className="text-blue-400 flex items-center gap-2">
              <Building2 size={18} />
              <span>VW_BRANCH_INVENTORY_SUMMARY</span>
            </div>
            <pre className="text-slate-300 leading-relaxed">
{`-- Branch-Level Inventory & Liability View
CREATE OR REPLACE VIEW vw_branch_inventory_summary AS
WITH BranchOwnership AS (
    -- Identify the home branch that initiated the batch
    SELECT DISTINCT ON (m.batch_id)
        m.batch_id,
        l.name as branch_name
    FROM BatchMovements m
    JOIN Locations l ON m.from_location_id = l.id
    WHERE l.category = 'Home'
    ORDER BY m.batch_id, m.timestamp ASC
),
BranchBatchData AS (
    SELECT 
        bo.branch_name,
        b.id as batch_id,
        b.quantity,
        b.asset_id,
        l_curr.name as current_location,
        l_curr.type as location_type,
        EXTRACT(DAY FROM (NOW() - b.created_at)) as age_days
    FROM BranchOwnership bo
    JOIN Batches b ON bo.batch_id = b.id
    JOIN Locations l_curr ON b.current_location_id = l_curr.id
    WHERE b.status != 'Lost'
)
SELECT 
    branch_name,
    SUM(quantity) as total_asset_count,
    JSON_AGG(JSON_BUILD_OBJECT(
        'loc', current_location,
        'type', location_type,
        'qty', quantity
    )) as location_breakdown,
    SUM(
        CASE WHEN fs.fee_type LIKE '%Rental%' 
        THEN quantity * fs.amount_zar * age_days ELSE 0 END
    ) as total_accrued_rental,
    SUM(
        CASE WHEN fs.fee_type LIKE '%Issue%' AND ts.id IS NULL 
        THEN quantity * fs.amount_zar ELSE 0 END
    ) as total_outstanding_issue_fees,
    -- Current Month Loss Recon
    (SELECT SUM(lost_quantity) FROM AssetLosses al 
     WHERE al.batch_id IN (SELECT id FROM Batches WHERE id = ANY(ARRAY_AGG(batch_id)))
     AND al.timestamp >= DATE_TRUNC('month', NOW())) as monthly_lost_qty
FROM BranchBatchData bbd
JOIN FeeSchedule fs ON bbd.asset_id = fs.asset_id AND fs.effective_to IS NULL
LEFT JOIN ThaanSlips ts ON bbd.batch_id = ts.batch_id
GROUP BY branch_name;
`}
            </pre>
          </div>

          <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-xs overflow-x-auto space-y-8">
            <div className="text-rose-400 flex items-center gap-2">
