  IN_TRANSIT = 'In Transit',
  RETURNING = 'Returning to Supplier',
  LOST = 'Lost/Written Off'
}

export enum LocationCategory {
  HOME = 'Home',
  EXTERNAL = 'External'
}

export enum AssetType {
  CRATE = 'Crate',
  PALLET = 'Pallet'
}

export enum FeeType {
  DAILY_RENTAL = 'Daily Rental (Supermarket)',
  ISSUE_FEE = 'Issue Fee (QSR)',
  REPLACEMENT_FEE = 'Replacement Fee (Lost Equipment)'
}

export enum MovementCondition {
  CLEAN = 'Clean',
  DIRTY = 'Dirty',
  DAMAGED = 'Damaged'
}

export type ClaimStatus = 'Lodged' | 'Under Assessment' | 'Returned for Assessment' | 'Accepted' | 'Rejected';

export interface User {
  id: string;
  name: string;
  role: string;
  branch_id: string;
}

export interface AssetMaster {
  id: string;
  name: string;
  type: AssetType;
  dimensions: string;
  material: string;
}

export interface FeeSchedule {
  id: string;
  asset_id: string;
  fee_type: FeeType;
  amount_zar: number;
  effective_from: string; // ISO Date
  effective_to: string | null; // NULL means currently active
}

export interface Location {
  id: string;
  name: string;
  type: LocationType;
  category: LocationCategory;
}

export interface LogisticsUnit {
  id: string;
  truck_plate: string;
  driver_name: string;
}

export interface Batch {
  id: string;
  asset_id: string;
  quantity: number;
  current_location_id: string;
  created_at: string;
  status: 'Pending' | 'Success' | 'Lost';
}

export interface BatchMovement {
  id: string;
  batch_id: string;
  from_location_id: string;
  to_location_id: string;
  logistics_id?: string;
  timestamp: string;
  condition: MovementCondition;
  origin_user_id: string;
}

export interface ThaanSlip {
  id: string;
  batch_id: string;
  doc_url: string;
  is_signed: boolean;
  signed_at: string | null;
}

export interface Claim {
  id: string;
  batch_id: string;
  driver_id: string;
  thaan_slip_id: string;
  type: 'Damaged' | 'Dirty';
  amount_claimed_zar: number;
  status: ClaimStatus;
  created_at: string;
  settled_at?: string;
}

export interface AssetLoss {
  id: string;
  batch_id: string;
  lost_quantity: number;
  last_known_location_id: string;
  last_driver_name?: string;
  last_truck_plate?: string;
  last_thaan_url?: string;
  reported_by: string;
  timestamp: string;
  notes: string;
  supplier_notified: boolean;
  supplier_invoice_ref?: string;
}

export interface ClaimAudit {
  id: string;
  claim_id: string;
  status_from: ClaimStatus | 'None';
  status_to: ClaimStatus;
  updated_by: string;
  timestamp: string;
  notes?: string;
}

export interface InventoryRecord {
  location_id: string;
  asset_id: string;
  quantity: number;
}

