import React, { useState } from 'react';
import { Database, Code, Table as TableIcon, Info, Calculator, ShieldCheck, AlertTriangle, Zap, CheckCircle2, Eye, Server, BarChart3, Skull, Building2, Award, Search, HandCoins } from 'lucide-react';

const SchemaView: React.FC = () => {
  const [activeView, setActiveView] = useState<'visual' | 'sql' | 'python' | 'simulator' | 'postgres'>('visual');

  // Simulator State
  const [simCondition, setSimCondition] = useState<'Clean' | 'Damaged'>('Clean');
  const [simThaan, setSimThaan] = useState(false);
  const [simClaimReceived, setSimClaimReceived] = useState(false);
  const [simDays, setSimDays] = useState(10);
  const [simAssetType, setSimAssetType] = useState<'Supermarket' | 'QSR'>('Supermarket');

  const entities = [
    { name: 'AssetMaster', fields: ['id', 'name', 'type', 'dimensions', 'material'] },
    { name: 'FeeSchedule', fields: ['id', 'asset_id (FK)', 'fee_type', 'amount_zar', 'effective_from', 'effective_to'] },
    { name: 'Locations', fields: ['id', 'name', 'type', 'category (Home/External)'] },
    { name: 'Batches', fields: ['id', 'asset_id (FK)', 'quantity', 'current_location_id (FK)', 'created_at', 'status'] },
    { name: 'AssetLosses', fields: ['id', 'batch_id (FK)', 'lost_qty', 'last_known_loc_id', 'last_driver', 'last_truck', 'thaan_url', 'timestamp', 'supplier_notified (BOOL)', 'supplier_invoice_ref'] },
    { name: 'Claims', fields: ['id', 'batch_id (FK)', 'driver_id (FK)', 'thaan_slip_id (FK)', 'status', 'created_at', 'settled_at'] },
    { name: 'SupplierCredits', fields: ['id', 'claim_id (FK)', 'amount_zar', 'processed_at'] },
    { name: 'Users', fields: ['id', 'name', 'role', 'branch_id'] }
  ];

  const calculateSimLiability = () => {
    let base = simAssetType === 'Supermarket' ? 5.00 : 120.00;
    let quantity = 100;
    if (simAssetType === 'Supermarket') {
      let activeDays = simDays;
      if (simCondition === 'Clean' && simThaan) activeDays = Math.min(simDays, 5);
      else if (simCondition === 'Damaged' && simClaimReceived) activeDays = Math.min(simDays, 8);
      return activeDays * base * quantity;
    } else {
      let fee = base * quantity;
      if (simThaan) fee = 0;
      return fee;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between overflow-x-auto pb-2">
        <div className="flex bg-slate-200 p-1 rounded-lg">
          <TabButton active={activeView === 'visual'} onClick={() => setActiveView('visual')} label="Visual Diagram" />
          <TabButton active={activeView === 'postgres'} onClick={() => setActiveView('postgres')} label="Postgres Workflow SQL" />
          <TabButton active={activeView === 'python'} onClick={() => setActiveView('python')} label="Liability Python" />
          <TabButton active={activeView === 'simulator'} onClick={() => setActiveView('simulator')} label="Accrual Simulator" />
        </div>
      </div>

      {activeView === 'visual' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 p-6 bg-slate-900 rounded-2xl border border-slate-800 overflow-auto max-h-[700px]">
          {entities.map(entity => (
            <div key={entity.name} className="bg-slate-800 border border-slate-700 rounded-lg overflow-hidden h-fit">
              <div className="px-4 py-2 bg-slate-700 border-b border-slate-600 flex items-center gap-2">
                <TableIcon size={14} className="text-emerald-400" />
                <span className="text-xs font-bold text-white tracking-wider uppercase">{entity.name}</span>
              </div>
              <div className="p-3 space-y-1">
                {entity.fields.map(field => (
                  <div key={field} className="text-xs text-slate-400 flex items-center gap-2 py-1 border-b border-slate-700/50 last:border-0">
                    <div className="w-1.5 h-1.5 rounded-full bg-slate-600" />
                    {field}
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      {activeView === 'postgres' && (
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
          <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-xs overflow-x-auto space-y-8">
            <div className="text-emerald-400 flex items-center gap-2">
              <HandCoins size={18} />
              <span>QRY_UNBILLED_LOSSES</span>
            </div>
            <pre className="text-slate-300 leading-relaxed">
{`-- Accounting Output: Summary of Notified but Unbilled Losses
SELECT 
    al.id as loss_ref,
    am.name as asset_type,
    al.lost_quantity as qty,
    fs.amount_zar as replacement_fee_at_time,
    al.lost_quantity * fs.amount_zar as total_loss_value,
    l.name as last_known_location,
    al.timestamp as loss_date
FROM AssetLosses al
JOIN Batches b ON al.batch_id = b.id
JOIN AssetMaster am ON b.asset_id = am.id
-- Find replacement fee active at time of loss
JOIN FeeSchedule fs ON am.id = fs.asset_id 
    AND fs.fee_type = 'Replacement Fee (Lost Equipment)'
    AND al.timestamp BETWEEN fs.effective_from 
    AND COALESCE(fs.effective_to, '9999-12-31')
JOIN Locations l ON al.last_known_location_id = l.id
WHERE al.supplier_notified = TRUE
  AND (al.supplier_invoice_ref IS NULL OR al.supplier_invoice_ref = '')
ORDER BY al.timestamp ASC;`}
            </pre>
            <div className="p-4 bg-emerald-900/50 rounded border border-emerald-800">
               <p className="text-[10px] text-emerald-300 font-bold uppercase mb-2">Audit Compliance Note</p>
               <p className="text-xs text-emerald-100 italic leading-relaxed">
                 This query is critical for Month-End Provisioning. It ensures the business is tracking liabilities already communicated to pooling partners before the physical invoice arrives.
               </p>
            </div>
          </div>

          <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-xs overflow-x-auto space-y-8">
            <div className="text-amber-400 flex items-center gap-2">
              <Award size={18} />
              <span>VW_EXECUTIVE_PERFORMANCE_AUDIT</span>
            </div>
            <pre className="text-slate-300 leading-relaxed">
{`-- Executive Cross-Branch Performance Report
CREATE OR REPLACE VIEW vw_executive_performance_audit AS
WITH LastMovements AS (
    SELECT DISTINCT ON (batch_id)
        batch_id, timestamp, logistics_id, from_location_id, to_location_id
    FROM BatchMovements ORDER BY batch_id, timestamp DESC
),
BranchRecon AS (
    SELECT 
        l_home.name as branch_name,
        b.id as batch_id,
        b.quantity,
        b.created_at,
        EXTRACT(DAY FROM (NOW() - lm.timestamp)) as idle_days,
        EXTRACT(DAY FROM (NOW() - b.created_at)) as total_age_days,
        l_curr.type as current_loc_type,
        l_curr.name as current_loc_name,
        lu.driver_name as last_driver
    FROM Batches b
    JOIN Locations l_home ON b.current_location_id = l_home.id
    JOIN Locations l_curr ON b.current_location_id = l_curr.id
    LEFT JOIN LastMovements lm ON b.id = lm.batch_id
    LEFT JOIN LogisticsUnits lu ON lm.logistics_id = lu.id
    WHERE b.status != 'Lost'
)
SELECT 
    branch_name,
    COUNT(CASE WHEN idle_days > 14 THEN 1 END) as stagnant_inventory_count,
    SUM(CASE WHEN current_loc_type IN ('Warehouse', 'Cold Storage') AND total_age_days > 21 
        THEN quantity * fs.amount_zar * total_age_days ELSE 0 END) as financial_drain_zar
FROM BranchRecon br
JOIN FeeSchedule fs ON br.asset_id = fs.asset_id AND fs.fee_type LIKE '%Rental%' AND fs.effective_to IS NULL
GROUP BY branch_name;`}
            </pre>
          </div>
        </div>
      )}

      {activeView === 'python' && (
        <div className="bg-slate-900 rounded-xl p-8 border border-slate-800 font-mono text-sm overflow-x-auto">
          <div className="text-blue-400 mb-4 flex items-center gap-2">
            <Calculator size={18} />
            <span>Accrued Liability Logic</span>
          </div>
          <pre className="text-slate-300 leading-relaxed">
{`def calculate_accrued_liability(batch_id, current_ts):
    batch = db.get_batch(batch_id)
    fee = db.get_historical_fee(batch.asset_id, batch.receipt_date)

    # Supermarket Logic
    if fee.type == "Daily Rental":
        thaan = db.get_signed_thaan(batch_id)
        claim = db.get_accepted_claim(batch_id)

        # Disputed Timer Rule:
        # Fee accrues during damage discovery until 'Accepted'
        if batch.condition in ["Dirty", "Damaged"] and not claim:
            end_date = current_ts # Still accruing liability
        elif claim:
            # Liability stopped once supplier accepts (Credit logic handles refund)
            end_date = claim.accepted_at 
        elif thaan:
            end_date = thaan.signed_at
        else:
            end_date = current_ts

        return (end_date - batch.receipt_date).days * fee.amount * batch.qty`}
          </pre>
        </div>
      )}

      {activeView === 'simulator' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm space-y-6">
            <h3 className="font-bold text-slate-800 flex items-center gap-2">
              <ShieldCheck className="text-emerald-500" size={20} />
              Accrual Logic Simulator
            </h3>

            <div className="space-y-4">
              <label className="block">
                <span className="text-xs font-bold text-slate-500 uppercase">Logic Mode</span>
                <select 
                  className="w-full mt-1 border border-slate-200 rounded p-2 text-sm"
                  value={simAssetType}
                  onChange={(e) => setSimAssetType(e.target.value as any)}
                >
                  <option value="Supermarket">Supermarket (Daily Rental)</option>
                  <option value="QSR">QSR (Issue Fee)</option>
                </select>
              </label>

              <div className="flex gap-4">
                <button 
                  onClick={() => setSimCondition(simCondition === 'Clean' ? 'Damaged' : 'Clean')}
                  className={`flex-1 p-3 rounded-lg border-2 text-xs font-bold transition-all ${simCondition === 'Clean' ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-rose-500 bg-rose-50 text-rose-700'}`}
                >
                  Condition: {simCondition}
                </button>
                <button 
                  onClick={() => setSimThaan(!simThaan)}
                  className={`flex-1 p-3 rounded-lg border-2 text-xs font-bold transition-all ${simThaan ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-slate-200 bg-slate-50 text-slate-400'}`}
                >
                  Signed THAAN: {simThaan ? 'YES' : 'NO'}
                </button>
              </div>

              {simCondition === 'Damaged' && (
                <button 
                  onClick={() => setSimClaimReceived(!simClaimReceived)}
                  className={`w-full p-3 rounded-lg border-2 text-xs font-bold transition-all ${simClaimReceived ? 'border-amber-500 bg-amber-50 text-amber-700' : 'border-slate-200 bg-slate-50 text-slate-400'}`}
                >
                  Supplier Accepted Claim: {simClaimReceived ? 'YES' : 'NO'}
                </button>
              )}

              <label className="block">
                <span className="text-xs font-bold text-slate-500 uppercase">Elapsed Days: {simDays}</span>
                <input 
                  type="range" min="1" max="30" value={simDays} 
                  onChange={(e) => setSimDays(parseInt(e.target.value))}
                  className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer mt-2"
                />
              </label>
            </div>
          </div>

          <div className="bg-slate-900 rounded-xl p-8 text-white flex flex-col justify-center items-center text-center">
            <Zap className="text-emerald-400 mb-4" size={48} />
            <h4 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-1">Calculated Accrued Liability</h4>
            <div className="text-5xl font-bold text-white mb-2">R {calculateSimLiability().toLocaleString()}</div>
            <div className="p-4 bg-slate-800 rounded-lg border border-slate-700 mt-6 max-w-xs">
              <p className="text-xs text-slate-400 leading-relaxed">
                {simAssetType === 'Supermarket' 
                  ? (simCondition === 'Damaged' && !simClaimReceived 
                      ? "Disputed Timer: Still accruing rental fees until Supplier officially accepts responsibility." 
                      : simThaan 
                        ? "Liability stopped. Transfer successful." 
                        : "Accruing daily rental fees...")
                  : (simThaan ? "Fee credited." : "Issue fee applied.")}
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

