import React, { useState, useEffect } from 'react';
import { MOCK_BATCHES, MOCK_MOVEMENTS, MOCK_LOCATIONS, MOCK_LOGISTICS, MOCK_THAANS, MOCK_ASSETS } from '../constants';
import { Skull, AlertTriangle, Truck, MapPin, User, FileText, CheckCircle2, XCircle, Search, Info, Database, CreditCard } from 'lucide-react';
import { LocationType, LossType } from '../types';

const LossRecorder: React.FC = () => {
  const [selectedBatchId, setSelectedBatchId] = useState<string>('');
  const [lossType, setLossType] = useState<LossType>(LossType.MISSING);
  const [isRechargeable, setIsRechargeable] = useState(false);
  const [lostQty, setLostQty] = useState<number>(0);
  const [notes, setNotes] = useState<string>('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);

  // Auto-fetched data
  const [lastKnown, setLastKnown] = useState<{
    location: string;
    locationType: LocationType;
    driver?: string;
    truck?: string;
    thaanUrl?: string;
    customerName?: string;
  } | null>(null);

  useEffect(() => {
    if (!selectedBatchId) {
      setLastKnown(null);
      return;
    }

    const batch = MOCK_BATCHES.find(b => b.id === selectedBatchId);
    if (!batch) return;

    const movements = MOCK_MOVEMENTS.filter(m => m.batch_id === selectedBatchId)
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

    const lastMv = movements[0];
    const loc = MOCK_LOCATIONS.find(l => l.id === (lastMv?.to_location_id || batch.current_location_id));
    const logistics = lastMv?.logistics_id ? MOCK_LOGISTICS.find(l => l.id === lastMv.logistics_id) : null;
    const thaan = MOCK_THAANS.find(t => t.batch_id === selectedBatchId);

    setLastKnown({
      location: loc?.name || 'Unknown',
      locationType: loc?.type || LocationType.WAREHOUSE,
      driver: logistics?.driver_name,
      truck: logistics?.truck_plate,
      thaanUrl: thaan?.doc_url,
      customerName: loc?.type === LocationType.AT_CUSTOMER ? loc.name : undefined
    });
    setLostQty(batch.quantity);

    // Auto-set Customer Liable if batch is at customer
    if (loc?.type === LocationType.AT_CUSTOMER) {
        setLossType(LossType.CUSTOMER_LIABLE);
        setIsRechargeable(true);
    } else {
        setLossType(LossType.MISSING);
        setIsRechargeable(false);
    }
  }, [selectedBatchId]);

  const handleRecordLoss = (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);

    setTimeout(() => {
      setSuccessMsg(`Loss Recorded: Batch ${selectedBatchId} written off as ${lossType}. SQL function triggered for settlement.`);
      setIsProcessing(false);
      setSelectedBatchId('');
      setNotes('');
    }, 1500);
  };

  const selectedBatch = MOCK_BATCHES.find(b => b.id === selectedBatchId);

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      {successMsg && (
        <div className="bg-emerald-50 border-l-4 border-emerald-500 p-4 rounded-r-lg flex items-center justify-between shadow-sm animate-in fade-in slide-in-from-top duration-300">
          <div className="flex items-center gap-3">
            <CheckCircle2 className="text-emerald-500" size={20} />
            <p className="text-sm font-bold text-emerald-800">{successMsg}</p>
          </div>
          <button onClick={() => setSuccessMsg(null)} className="text-emerald-400 hover:text-emerald-600 transition-colors">
            <XCircle size={18} />
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="px-6 py-4 bg-slate-900 text-white flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Skull size={18} className="text-rose-400" />
                <h3 className="font-bold text-sm uppercase tracking-widest">Asset Loss Report</h3>
              </div>
            </div>

            <form onSubmit={handleRecordLoss} className="p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <label className="block space-y-2">
                  <span className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                    <Search size={14} /> Investigation Target
                  </span>
                  <select 
                    className="w-full border border-slate-200 rounded-xl p-4 text-sm focus:ring-2 focus:ring-rose-500 bg-slate-50 outline-none"
                    value={selectedBatchId}
                    onChange={e => setSelectedBatchId(e.target.value)}
                  >
                    <option value="">-- Choose a Batch --</option>
                    {MOCK_BATCHES.filter(b => b.status !== 'Lost').map(b => (
                      <option key={b.id} value={b.id}>
                        {b.id} ({b.quantity} {MOCK_ASSETS.find(a => a.id === b.asset_id)?.name})
                      </option>
                    ))}
                  </select>
                </label>

                <label className="block space-y-2">
                  <span className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                    Loss Categorization
                  </span>
                  <select 
                    className="w-full border border-slate-200 rounded-xl p-4 text-sm focus:ring-2 focus:ring-rose-500 bg-slate-50 outline-none"
                    value={lossType}
                    onChange={e => setLossType(e.target.value as LossType)}
                  >
                    {Object.values(LossType).map(lt => (
                      <option key={lt} value={lt}>{lt}</option>
                    ))}
                  </select>
                </label>
              </div>

              {selectedBatchId && (
                <div className="grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-bottom duration-300">
                  <label className="block space-y-2">
                    <span className="text-[10px] font-bold text-slate-400 uppercase">Quantity Lost</span>
                    <input 
                      type="number" 
                      max={selectedBatch?.quantity}
                      min={1}
                      className="w-full border border-slate-200 rounded-xl p-4 text-sm bg-white"
                      value={lostQty}
                      onChange={e => setLostQty(parseInt(e.target.value) || 0)}
                    />
                  </label>
                  <div className="flex flex-col justify-end gap-3">
                    <label className="flex items-center gap-3 cursor-pointer group">
                      <div className={`w-6 h-6 rounded border-2 flex items-center justify-center transition-all ${isRechargeable ? 'bg-amber-500 border-amber-500' : 'bg-white border-slate-200'}`}>
                         <input 
                           type="checkbox" 
                           className="hidden" 
                           checked={isRechargeable}
                           onChange={e => setIsRechargeable(e.target.checked)}
                         />
                         {isRechargeable && <CreditCard size={14} className="text-white" />}
                      </div>
                      <span className="text-[10px] font-bold text-slate-500 uppercase">Flag as Rechargeable</span>
                    </label>
                  </div>
                </div>
              )}

              {lastKnown && (
                <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100 space-y-4">
                  <div className="grid grid-cols-2 gap-6">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase">Last Known Loc</p>
                      <p className="text-sm font-bold text-slate-700">{lastKnown.location}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase">Last Operator</p>
                      <p className="text-sm font-bold text-slate-700">{lastKnown.driver || 'N/A'}</p>
                    </div>
                  </div>
                </div>
              )}

              <label className="block space-y-2">
                <span className="text-xs font-bold text-slate-500 uppercase">Final Investigation Notes</span>
                <textarea 
                  className="w-full border border-slate-200 rounded-xl p-4 text-sm h-32 bg-slate-50 resize-none outline-none focus:ring-2 focus:ring-rose-500"
                  placeholder="Detail the cause of loss..."
                  value={notes}
                  onChange={e => setNotes(e.target.value)}
                />
              </label>

              <button 
                type="submit" 
                disabled={!selectedBatchId || isProcessing}
                className={`w-full font-bold py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3 ${
                  !selectedBatchId 
                    ? 'bg-slate-100 text-slate-400' 
                    : 'bg-rose-600 text-white hover:bg-rose-700'
                }`}
              >
                {isProcessing ? 'Saving...' : 'Execute Write-Off'}
              </button>
            </form>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm space-y-4">
             <h4 className="font-bold text-slate-800 text-xs uppercase tracking-widest flex items-center gap-2">
               <AlertTriangle className="text-amber-500" size={16} /> Loss Type Impact
             </h4>
             <div className="space-y-4">
                <div className="border-l-2 border-emerald-500 pl-3">
                   <p className="text-[10px] font-black text-slate-800 uppercase">Missing/Lost</p>
                   <p className="text-[10px] text-slate-500">100% Replacement Fee applied immediately.</p>
                </div>
                <div className="border-l-2 border-blue-500 pl-3">
                   <p className="text-[10px] font-black text-slate-800 uppercase">Scrapped</p>
                   <p className="text-[10px] text-slate-500">Net Cost = Replacement Fee - 10% Salvage Credit.</p>
                </div>
                <div className="border-l-2 border-amber-500 pl-3">
                   <p className="text-[10px] font-black text-slate-800 uppercase">Customer Liable</p>
                   <p className="text-[10px] text-slate-500">Recharge report generated for Accounts Receivable.</p>
                </div>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LossRecorder;

import React, { useState } from 'react';
import { MOCK_LOSSES, MOCK_FEES, MOCK_BATCHES, MOCK_ASSETS, MOCK_LOCATIONS } from '../constants';
import { AssetLoss, FeeType, LossType } from '../types';
import { 
  HandCoins, 
  Bell, 
  FileText, 
  CheckCircle2, 
  AlertTriangle, 
  Search, 
  ArrowRight, 
  Calculator, 
  MapPin, 
  History, 
  Zap,
  Printer,
  ChevronDown,
  CreditCard,
  Trash2
} from 'lucide-react';

const SupplierRecon: React.FC = () => {
  const [losses, setLosses] = useState<AssetLoss[]>(MOCK_LOSSES);
  const [filter, setFilter] = useState<'all' | 'notified' | 'unbilled'>('all');

  // Helper: Find replacement fee for asset at time of loss
  const getReplacementFee = (assetId: string, timestamp: string) => {
    return MOCK_FEES.find(f => 
      f.asset_id === assetId && 
      f.fee_type === FeeType.REPLACEMENT_FEE &&
      new Date(timestamp) >= new Date(f.effective_from) &&
      (!f.effective_to || new Date(timestamp) <= new Date(f.effective_to))
    );
  };

  const handleToggleNotification = (id: string) => {
    setLosses(prev => prev.map(l => 
      l.id === id ? { ...l, supplier_notified: !l.supplier_notified } : l
    ));
  };

  const calculateSettlement = (loss: AssetLoss) => {
    const batch = MOCK_BATCHES.find(b => b.id === loss.batch_id);
    const fee = getReplacementFee(batch?.asset_id || '', loss.timestamp);
    const baseAmount = loss.lost_quantity * (fee?.amount_zar || 0);

    if (loss.loss_type === LossType.SCRAPPED) {
        return baseAmount * 0.9; // 10% Salvage Credit logic
    }
    return baseAmount;
  };

  const filteredLosses = losses.filter(l => {
    if (filter === 'notified') return l.supplier_notified;
    if (filter === 'unbilled') return l.supplier_notified && !l.supplier_invoice_ref;
    return true;
  });

  const totalUnbilledLossValue = losses
    .filter(l => l.supplier_notified && !l.supplier_invoice_ref)
    .reduce((total, l) => total + calculateSettlement(l), 0);

  return (
    <div className="space-y-8 pb-20">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-slate-900 text-white p-6 rounded-2xl shadow-xl shadow-slate-200">
          <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Unbilled Settlement Exposure</p>
          <p className="text-3xl font-bold">R {totalUnbilledLossValue.toLocaleString()}</p>
          <div className="flex items-center gap-1 text-[10px] text-amber-400 font-bold mt-2 uppercase">
            <AlertTriangle size={12} /> After Scrapped/Salvage Credits
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex items-center justify-between">
          <div>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Rechargeable Value</p>
            <p className="text-2xl font-bold text-amber-600">
               R {losses.filter(l => l.is_rechargeable).reduce((acc, l) => acc + calculateSettlement(l), 0).toLocaleString()}
            </p>
          </div>
          <CreditCard className="text-amber-500 opacity-20" size={40} />
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex items-center justify-between">
          <div>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Audit Trail Active</p>
            <p className="text-2xl font-bold text-emerald-600">100%</p>
          </div>
          <CheckCircle2 className="text-emerald-500 opacity-20" size={40} />
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="px-6 py-4 bg-slate-50 border-b border-slate-200 flex flex-wrap justify-between items-center gap-4">
          <div className="flex items-center gap-2">
            <HandCoins size={18} className="text-emerald-600" />
            <h3 className="font-bold text-slate-800 text-sm uppercase tracking-widest">Supplier Reconciliation</h3>
          </div>

          <div className="flex gap-2">
            <FilterButton active={filter === 'all'} onClick={() => setFilter('all')} label="All" />
            <FilterButton active={filter === 'unbilled'} onClick={() => setFilter('unbilled')} label="Unbilled" />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-[10px] font-black text-slate-400 uppercase tracking-tighter border-b border-slate-100 bg-slate-50/50">
                <th className="px-8 py-4">Ref & Type</th>
                <th className="px-8 py-4">Asset Detail</th>
                <th className="px-8 py-4">Forensics</th>
                <th className="px-8 py-4 text-right">Settlement (ZAR)</th>
                <th className="px-8 py-4">Billing State</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredLosses.map(loss => {
                const batch = MOCK_BATCHES.find(b => b.id === loss.batch_id);
                const asset = MOCK_ASSETS.find(a => a.id === batch?.asset_id);
                const fee = getReplacementFee(asset?.id || '', loss.timestamp);
                const settlement = calculateSettlement(loss);
                const location = MOCK_LOCATIONS.find(l => l.id === loss.last_known_location_id);

                return (
                  <tr key={loss.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-8 py-6">
                      <p className="text-sm font-bold text-slate-800">#{loss.id}</p>
                      <span className={`text-[8px] font-black px-1.5 py-0.5 rounded uppercase ${
                          loss.loss_type === LossType.MISSING ? 'bg-slate-100 text-slate-600' :
                          loss.loss_type === LossType.SCRAPPED ? 'bg-blue-100 text-blue-700' :
                          'bg-amber-100 text-amber-700'
                      }`}>
                          {loss.loss_type}
                      </span>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-3">
                        <div>
                          <p className="text-xs font-bold text-slate-700">{asset?.name}</p>
                          <p className="text-[10px] text-slate-400">{loss.lost_quantity} Units</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="space-y-1">
                        <div className="flex items-center gap-1.5 text-[10px] font-medium text-slate-600">
                          <MapPin size={10} className="text-rose-500" /> {location?.name}
                        </div>
                        {loss.is_rechargeable && (
                           <div className="flex items-center gap-1.5 text-[10px] text-amber-600 font-bold uppercase">
                             <CreditCard size={10} /> Rechargeable
                           </div>
                        )}
                      </div>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <div className="space-y-0.5">
                        <p className="text-sm font-black text-slate-800">R {settlement.toLocaleString()}</p>
                        <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">
                            {loss.loss_type === LossType.SCRAPPED ? 'Salvage Rate Applied' : `Rate: R ${fee?.amount_zar.toFixed(2)}`}
                        </p>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex flex-col gap-2">
                        <label className="flex items-center gap-2 cursor-pointer">
                          <div 
                            onClick={() => handleToggleNotification(loss.id)}
                            className={`w-8 h-4 rounded-full relative transition-colors ${loss.supplier_notified ? 'bg-emerald-500' : 'bg-slate-200'}`}
                          >
                            <div className={`absolute top-0.5 left-0.5 w-3 h-3 rounded-full bg-white transition-transform ${loss.supplier_notified ? 'translate-x-4' : 'translate-x-0'}`} />
                          </div>
                          <span className="text-[10px] font-bold text-slate-500 uppercase">Notified</span>
                        </label>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

