CREATE OR REPLACE FUNCTION fn_calculate_loss_settlement(
    p_loss_id UUID,
    p_branch_id UUID DEFAULT NULL
) 
RETURNS TABLE (
    total_settlement NUMERIC,
    is_rechargeable BOOLEAN,
    branch_name TEXT
) AS $$
DECLARE
    v_loss_type TEXT;
    v_asset_id UUID;
    v_qty INT;
    v_ts TIMESTAMP;
    v_base_rate NUMERIC;
    v_salvage_rate NUMERIC := 0.10; -- 10% Salvage Credit for Scrapped
BEGIN
    -- Fetch Loss Context
    SELECT 
        al.loss_type, b.asset_id, al.lost_qty, al.timestamp, l.name, al.is_rechargeable
    INTO 
        v_loss_type, v_asset_id, v_qty, v_ts, branch_name, is_rechargeable
    FROM AssetLosses al
    JOIN Batches b ON al.batch_id = b.id
    JOIN Locations l ON b.branch_id = l.id
    WHERE al.id = p_loss_id
      AND (p_branch_id IS NULL OR b.branch_id = p_branch_id);

    -- Get Replacement Fee at time of loss
    SELECT amount_zar INTO v_base_rate FROM FeeSchedule
    WHERE asset_id = v_asset_id AND fee_type = 'Replacement Fee (Lost Equipment)'
      AND v_ts BETWEEN effective_from AND COALESCE(effective_to, '9999-12-31')
    LIMIT 1;

    -- Type-Specific Logic
    CASE v_loss_type
        WHEN 'Missing/Lost' THEN
            total_settlement := v_qty * v_base_rate;
        WHEN 'Scrapped (Unrepairable)' THEN
            total_settlement := (v_qty * v_base_rate) * (1 - v_salvage_rate);
        WHEN 'Customer Liable' THEN
            total_settlement := v_qty * v_base_rate;
            -- Logic to flag rechargeable is handled by v_is_rechargeable selection
        ELSE
            total_settlement := v_qty * v_base_rate;
    END CASE;

    RETURN NEXT;
END;
$$ LANGUAGE plpgsql;`}
