        thaan = db.get_signed_thaan(batch_id)
        claim = db.get_accepted_claim(batch_id)

        # Disputed Timer Rule:
        # Fee accrues during damage discovery until 'Accepted'
        if batch.condition in ["Dirty", "Damaged"] and not claim:
            end_date = current_ts # Still accruing liability
        elif claim:
            # Liability stopped once supplier accepts (Credit logic handles refund)
            end_date = claim.accepted_at 
        elif thaan:
            end_date = thaan.signed_at
        else:
            end_date = current_ts

        return (end_date - batch.receipt_date).days * fee.amount * batch.qty`}
          </pre>
        </div>
      )}

      {activeView === 'simulator' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm space-y-6">
            <h3 className="font-bold text-slate-800 flex items-center gap-2">
              <ShieldCheck className="text-emerald-500" size={20} />
              Accrual Logic Simulator
            </h3>

            <div className="space-y-4">
              <label className="block">
                <span className="text-xs font-bold text-slate-500 uppercase">Logic Mode</span>
                <select 
                  className="w-full mt-1 border border-slate-200 rounded p-2 text-sm"
                  value={simAssetType}
                  onChange={(e) => setSimAssetType(e.target.value as any)}
                >
                  <option value="Supermarket">Supermarket (Daily Rental)</option>
                  <option value="QSR">QSR (Issue Fee)</option>
                </select>
              </label>

              <div className="flex gap-4">
                <button 
                  onClick={() => setSimCondition(simCondition === 'Clean' ? 'Damaged' : 'Clean')}
                  className={`flex-1 p-3 rounded-lg border-2 text-xs font-bold transition-all ${simCondition === 'Clean' ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-rose-500 bg-rose-50 text-rose-700'}`}
                >
                  Condition: {simCondition}
                </button>
                <button 
                  onClick={() => setSimThaan(!simThaan)}
                  className={`flex-1 p-3 rounded-lg border-2 text-xs font-bold transition-all ${simThaan ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-slate-200 bg-slate-50 text-slate-400'}`}
                >
                  Signed THAAN: {simThaan ? 'YES' : 'NO'}
                </button>
              </div>

              {simCondition === 'Damaged' && (
                <button 
                  onClick={() => setSimClaimReceived(!simClaimReceived)}
                  className={`w-full p-3 rounded-lg border-2 text-xs font-bold transition-all ${simClaimReceived ? 'border-amber-500 bg-amber-50 text-amber-700' : 'border-slate-200 bg-slate-50 text-slate-400'}`}
                >
                  Supplier Accepted Claim: {simClaimReceived ? 'YES' : 'NO'}
                </button>
              )}

              <label className="block">
                <span className="text-xs font-bold text-slate-500 uppercase">Elapsed Days: {simDays}</span>
                <input 
                  type="range" min="1" max="30" value={simDays} 
                  onChange={(e) => setSimDays(parseInt(e.target.value))}
                  className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer mt-2"
                />
              </label>
            </div>
          </div>

          <div className="bg-slate-900 rounded-xl p-8 text-white flex flex-col justify-center items-center text-center">
            <Zap className="text-emerald-400 mb-4" size={48} />
            <h4 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-1">Calculated Accrued Liability</h4>
            <div className="text-5xl font-bold text-white mb-2">R {calculateSimLiability().toLocaleString()}</div>
            <div className="p-4 bg-slate-800 rounded-lg border border-slate-700 mt-6 max-w-xs">
              <p className="text-xs text-slate-400 leading-relaxed">
                {simAssetType === 'Supermarket' 
                  ? (simCondition === 'Damaged' && !simClaimReceived 
                      ? "Disputed Timer: Still accruing rental fees until Supplier officially accepts responsibility." 
                      : simThaan 
                        ? "Liability stopped. Transfer successful." 
                        : "Accruing daily rental fees...")
                  : (simThaan ? "Fee credited." : "Issue fee applied.")}
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

