import React, { useState } from 'react';
import { MOCK_LOSSES, MOCK_FEES, MOCK_BATCHES, MOCK_ASSETS, MOCK_LOCATIONS } from '../constants';
import { AssetLoss, FeeType, LossType } from '../types';
import { 
  HandCoins, 
