enum NavItem {
  DASHBOARD = 'dashboard',
  INVENTORY = 'inventory',
  EXECUTIVE = 'executive',
  FINANCIALS = 'financials',
  SETTLEMENT = 'settlement',
  ASSETS = 'assets',
  TRACKER = 'tracker',
  LOGISTICS = 'logistics',
  LOSSES = 'losses',
  SUPPLIER_RECON = 'supplier-recon',
  CLAIMS = 'claims',
  SCHEMA = 'schema'
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<NavItem>(NavItem.DASHBOARD);

  // RBAC State - Current User
  const [currentUser, setCurrentUser] = useState<User>({
    id: 'U-001',
    name: 'John Dlamini',
    role: UserRole.ADMIN,
    branch_id: 'LOC-JHB-01'
  });

  const [isRoleModalOpen, setIsRoleModalOpen] = useState(false);

  // RBAC Middleware Logic (Frontend Implementation)
  const canAccess = (permission: Permission, contextBranchId?: string): boolean => {
    const role = currentUser.role;

    switch (role) {
      case UserRole.ADMIN:
        return true; // Full access

      case UserRole.MANAGER:
        // Branch check: can only manage if it's their branch or global dashboard
        if (contextBranchId && contextBranchId !== currentUser.branch_id) return false;

        if (permission === 'MANAGE_FEES' || permission === 'MANAGE_USERS') return false;
        if (permission === 'VIEW_SETTLEMENT') return true; // Can view report
        return true;

      case UserRole.STAFF:
        if (permission === 'WRITE_MOVEMENTS' || permission === 'MANAGE_LOSSES') return true;
        if (permission === 'VIEW_DASHBOARD') return true;
        return false;

      case UserRole.EXECUTIVE:
        if (permission === 'VIEW_DASHBOARD' || permission === 'VIEW_SETTLEMENT') return true;
        return false;

      default:
        return false;
    }
  };

  const navPermissions: Record<NavItem, Permission> = {
    [NavItem.DASHBOARD]: 'VIEW_DASHBOARD',
    [NavItem.INVENTORY]: 'VIEW_DASHBOARD',
    [NavItem.EXECUTIVE]: 'VIEW_DASHBOARD',
    [NavItem.FINANCIALS]: 'VIEW_DASHBOARD',
    [NavItem.SETTLEMENT]: 'VIEW_SETTLEMENT',
    [NavItem.ASSETS]: 'VIEW_DASHBOARD',
    [NavItem.TRACKER]: 'VIEW_DASHBOARD',
    [NavItem.LOGISTICS]: 'WRITE_MOVEMENTS',
    [NavItem.LOSSES]: 'MANAGE_LOSSES',
    [NavItem.SUPPLIER_RECON]: 'VIEW_SETTLEMENT',
    [NavItem.CLAIMS]: 'APPROVE_CLAIMS',
    [NavItem.SCHEMA]: 'VIEW_DASHBOARD',
  };

  const renderContent = () => {
    const permission = navPermissions[activeTab];
    if (!canAccess(permission)) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400">
           <ShieldCheck size={64} className="mb-4 opacity-20" />
           <h3 className="text-xl font-bold text-slate-800">Access Denied</h3>
           <p className="text-sm">Your profile ({currentUser.role}) does not have permission to view this module.</p>
        </div>
      );
    }

    switch (activeTab) {
      case NavItem.DASHBOARD: return <DashboardView />;
      case NavItem.INVENTORY: return <InventoryDashboard />;
      case NavItem.EXECUTIVE: return <ExecutiveReport />;
      case NavItem.FINANCIALS: return <FinancialReport />;
      case NavItem.SETTLEMENT: return <SupplierSettlementReport isAdmin={currentUser.role === UserRole.ADMIN} />;
      case NavItem.ASSETS: return <AssetList isAdmin={currentUser.role === UserRole.ADMIN} />;
      case NavItem.TRACKER: return <BatchTracker />;
      case NavItem.LOGISTICS: return <LogisticsOps />;
      case NavItem.LOSSES: return <LossRecorder />;
      case NavItem.SUPPLIER_RECON: return <SupplierRecon />;
      case NavItem.CLAIMS: return <ClaimsManager isManager={currentUser.role === UserRole.MANAGER || currentUser.role === UserRole.ADMIN} />;
      case NavItem.SCHEMA: return <SchemaView />;
      default: return <DashboardView />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col fixed h-full z-10">
        <div className="p-6 flex items-center gap-3 border-b border-slate-800">
          <div className="bg-amber-500 p-2 rounded-lg">
            <Package className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="font-black text-xl leading-tight tracking-tighter">SHUKU</h1>
            <p className="text-[10px] text-amber-400 font-bold uppercase tracking-widest">Lupo Bakery Pro</p>
          </div>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-1 overflow-y-auto">
          {canAccess('VIEW_DASHBOARD') && (
            <>
              <SidebarButton active={activeTab === NavItem.DASHBOARD} onClick={() => setActiveTab(NavItem.DASHBOARD)} icon={<LayoutDashboard size={18} />} label="Dashboard" />
              <SidebarButton active={activeTab === NavItem.INVENTORY} onClick={() => setActiveTab(NavItem.INVENTORY)} icon={<Globe size={18} />} label="Global Inventory" />
              <SidebarButton active={activeTab === NavItem.EXECUTIVE} onClick={() => setActiveTab(NavItem.EXECUTIVE)} icon={<Award size={18} />} label="Executive Audit" />
              <SidebarButton active={activeTab === NavItem.FINANCIALS} onClick={() => setActiveTab(NavItem.FINANCIALS)} icon={<BarChart3 size={18} />} label="Branch Health" />
            </>
