  EXECUTIVE: 'Dashboard Viewer'
};

const validateAccess = (user, permission, context = {}) => {
  // 1. System Admin bypass
  if (user.role === ROLES.ADMIN) return true;

  switch (permission) {
    case 'UPDATE_FEES':
    case 'MANAGE_USERS':
      // Annual Fee Changes restricted to Admin
      return user.role === ROLES.ADMIN;

    case 'VIEW_SETTLEMENT':
