const authMiddleware = (permission) => (req, res, next) => {
  const user = req.user;
  const context = { branch_id: req.body.branch_id || req.params.branch_id };

  if (validateAccess(user, permission, context)) {
    next();
  } else {
    res.status(403).json({ 
      error: 'Insufficient Permissions', 
      required: permission,
      profile: user.role 
    });
  }
};`}
