enum NavItem {
  DASHBOARD = 'dashboard',
  INVENTORY = 'inventory',
  EXECUTIVE = 'executive',
  FINANCIALS = 'financials',
  SETTLEMENT = 'settlement',
  ASSETS = 'assets',
  TRACKER = 'tracker',
  LOGISTICS = 'logistics',
  LOSSES = 'losses',
  SUPPLIER_RECON = 'supplier-recon',
  CLAIMS = 'claims',
  SCHEMA = 'schema',
  AUDIT = 'audit'
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<NavItem>(NavItem.DASHBOARD);

  // RBAC State - Current User
  const [currentUser, setCurrentUser] = useState<User>({
    id: 'U-001',
    name: 'John Dlamini',
    role: UserRole.ADMIN,
    branch_id: 'LOC-JHB-01'
  });

  const [isRoleModalOpen, setIsRoleModalOpen] = useState(false);

  // RBAC Middleware Logic (Frontend Implementation)
  const canAccess = (permission: Permission, contextBranchId?: string): boolean => {
    const role = currentUser.role;

    switch (role) {
      case UserRole.ADMIN:
        return true; // Full access

      case UserRole.MANAGER:
        if (contextBranchId && contextBranchId !== currentUser.branch_id) return false;
        if (permission === 'MANAGE_FEES' || permission === 'MANAGE_USERS' || permission === 'VIEW_AUDIT_LOGS') return false;
        if (permission === 'VIEW_SETTLEMENT') return true; 
        return true;

      case UserRole.STAFF:
        if (permission === 'WRITE_MOVEMENTS' || permission === 'MANAGE_LOSSES') return true;
        if (permission === 'VIEW_DASHBOARD') return true;
        return false;

      case UserRole.EXECUTIVE:
        if (permission === 'VIEW_DASHBOARD' || permission === 'VIEW_SETTLEMENT') return true;
        return false;

      default:
        return false;
    }
  };

  const navPermissions: Record<NavItem, Permission> = {
    [NavItem.DASHBOARD]: 'VIEW_DASHBOARD',
    [NavItem.INVENTORY]: 'VIEW_DASHBOARD',
    [NavItem.EXECUTIVE]: 'VIEW_DASHBOARD',
    [NavItem.FINANCIALS]: 'VIEW_DASHBOARD',
    [NavItem.SETTLEMENT]: 'VIEW_SETTLEMENT',
    [NavItem.ASSETS]: 'VIEW_DASHBOARD',
    [NavItem.TRACKER]: 'VIEW_DASHBOARD',
    [NavItem.LOGISTICS]: 'WRITE_MOVEMENTS',
    [NavItem.LOSSES]: 'MANAGE_LOSSES',
    [NavItem.SUPPLIER_RECON]: 'VIEW_SETTLEMENT',
    [NavItem.CLAIMS]: 'APPROVE_CLAIMS',
    [NavItem.SCHEMA]: 'VIEW_DASHBOARD',
    [NavItem.AUDIT]: 'VIEW_AUDIT_LOGS'
  };

  const renderContent = () => {
    const permission = navPermissions[activeTab];
    if (!canAccess(permission)) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400">
           <ShieldCheck size={64} className="mb-4 opacity-20" />
           <h3 className="text-xl font-bold text-slate-800">Access Denied</h3>
           <p className="text-sm">Your profile ({currentUser.role}) does not have permission to view this module.</p>
        </div>
      );
    }

    switch (activeTab) {
      case NavItem.DASHBOARD: return <DashboardView currentUser={currentUser} />;
      case NavItem.INVENTORY: return <InventoryDashboard />;
      case NavItem.EXECUTIVE: return <ExecutiveReport />;
      case NavItem.FINANCIALS: return <FinancialReport />;
      case NavItem.SETTLEMENT: return <SupplierSettlementReport isAdmin={currentUser.role === UserRole.ADMIN} />;
      case NavItem.ASSETS: return <AssetList isAdmin={currentUser.role === UserRole.ADMIN} />;
      case NavItem.TRACKER: return <BatchTracker />;
      case NavItem.LOGISTICS: return <LogisticsOps currentUser={currentUser} />;
      case NavItem.LOSSES: return <LossRecorder currentUser={currentUser} />;
      case NavItem.SUPPLIER_RECON: return <SupplierRecon />;
      case NavItem.CLAIMS: return <ClaimsManager isManager={currentUser.role === UserRole.MANAGER || currentUser.role === UserRole.ADMIN} />;
      case NavItem.SCHEMA: return <SchemaView />;
      case NavItem.AUDIT: return <AuditView />;
      default: return <DashboardView currentUser={currentUser} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col fixed h-full z-10 shadow-2xl">
        <div className="p-6 flex items-center gap-3 border-b border-slate-800">
          <div className="bg-amber-500 p-2 rounded-lg shadow-lg shadow-amber-900/40">
            <Package className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="font-black text-xl leading-tight tracking-tighter">SHUKU</h1>
            <p className="text-[10px] text-amber-400 font-bold uppercase tracking-widest">Lupo Bakery Pro</p>
          </div>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-1 overflow-y-auto">
          {canAccess('VIEW_DASHBOARD') && (
            <>
              <SidebarButton active={activeTab === NavItem.DASHBOARD} onClick={() => setActiveTab(NavItem.DASHBOARD)} icon={<LayoutDashboard size={18} />} label="Dashboard" />
              <SidebarButton active={activeTab === NavItem.INVENTORY} onClick={() => setActiveTab(NavItem.INVENTORY)} icon={<Globe size={18} />} label="Global Inventory" />
              <SidebarButton active={activeTab === NavItem.EXECUTIVE} onClick={() => setActiveTab(NavItem.EXECUTIVE)} icon={<Award size={18} />} label="Executive Audit" />
              <SidebarButton active={activeTab === NavItem.FINANCIALS} onClick={() => setActiveTab(NavItem.FINANCIALS)} icon={<BarChart3 size={18} />} label="Branch Health" />
            </>
          )}

          {canAccess('VIEW_SETTLEMENT') && (
            <SidebarButton active={activeTab === NavItem.SETTLEMENT} onClick={() => setActiveTab(NavItem.SETTLEMENT)} icon={<Receipt size={18} />} label="Supplier Settlement" />
          )}

          <div className="pt-4 pb-2 px-4">
             <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Operations</span>
          </div>

          <SidebarButton active={activeTab === NavItem.ASSETS} onClick={() => setActiveTab(NavItem.ASSETS)} icon={<Database size={18} />} label="SHUKU Master" />

          {canAccess('WRITE_MOVEMENTS') && (
            <SidebarButton active={activeTab === NavItem.LOGISTICS} onClick={() => setActiveTab(NavItem.LOGISTICS)} icon={<ClipboardList size={18} />} label="Logistics Manifest" />
          )}

          {canAccess('MANAGE_LOSSES') && (
            <SidebarButton active={activeTab === NavItem.LOSSES} onClick={() => setActiveTab(NavItem.LOSSES)} icon={<Skull size={18} />} label="Write-off Tool" />
          )}

          {canAccess('VIEW_SETTLEMENT') && (
            <SidebarButton active={activeTab === NavItem.SUPPLIER_RECON} onClick={() => setActiveTab(NavItem.SUPPLIER_RECON)} icon={<HandCoins size={18} />} label="Supplier Recon" />
          )}

          <SidebarButton active={activeTab === NavItem.TRACKER} onClick={() => setActiveTab(NavItem.TRACKER)} icon={<History size={18} />} label="Batch Lifecycle" />

          {canAccess('APPROVE_CLAIMS') && (
            <SidebarButton active={activeTab === NavItem.CLAIMS} onClick={() => setActiveTab(NavItem.CLAIMS)} icon={<AlertTriangle size={18} />} label="Claims Queue" />
          )}

          <div className="pt-4 mt-4 border-t border-slate-800">
            {canAccess('VIEW_AUDIT_LOGS') && (
              <SidebarButton active={activeTab === NavItem.AUDIT} onClick={() => setActiveTab(NavItem.AUDIT)} icon={<Activity size={18} />} label="System Audit" />
            )}
            <SidebarButton active={activeTab === NavItem.SCHEMA} onClick={() => setActiveTab(NavItem.SCHEMA)} icon={<Search size={18} />} label="System Arch" />
          </div>
        </nav>

        <div className="p-4 bg-slate-950/50 border-t border-slate-800 relative">
          <button 
            onClick={() => setIsRoleModalOpen(!isRoleModalOpen)}
            className="w-full text-left group bg-slate-800/50 hover:bg-slate-800 p-2 rounded-xl transition-all border border-slate-800"
          >
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 rounded-full bg-amber-500 flex items-center justify-center text-xs font-black text-slate-900 group-hover:scale-110 transition-transform shadow-inner shadow-black/20">
                {currentUser.name.charAt(0)}
              </div>
              <div className="overflow-hidden">
                <p className="text-xs font-bold truncate group-hover:text-amber-400 transition-colors">{currentUser.name}</p>
                <p className="text-[10px] text-slate-500 uppercase font-black tracking-tighter">{currentUser.role}</p>
              </div>
            </div>
          </button>

          {isRoleModalOpen && (
            <div className="absolute bottom-full left-4 right-4 mb-2 bg-slate-800 rounded-xl border border-slate-700 shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-2 z-50">
              <div className="p-3 border-b border-slate-700 bg-slate-900">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Switch Profile (RBAC Test)</p>
              </div>
              {Object.values(UserRole).map(role => (
                <button 
