import React, { useState, useRef } from 'react';
import { Truck, MapPin, ClipboardList, CheckCircle2, AlertTriangle, ArrowRight, User, Package, Zap, Camera, FileText, Trash2, X, UserCheck } from 'lucide-react';
import { MOCK_BATCHES, MOCK_LOCATIONS, MOCK_LOGISTICS, MOCK_ASSETS, MOCK_INVENTORY, MOCK_MOVEMENTS, MOCK_USERS } from '../constants';
import { MovementCondition, LocationType, AssetType, User as UserType } from '../types';

interface LogisticsOpsProps {
  currentUser: UserType;
}

const LogisticsOps: React.FC<LogisticsOpsProps> = ({ currentUser }) => {
  // Form State
  const [origin, setOrigin] = useState(MOCK_LOCATIONS[0].id);
  const [destination, setDestination] = useState(MOCK_LOCATIONS[3].id); // Default to In Transit
  const [logisticsId, setLogisticsId] = useState(MOCK_LOGISTICS[0].id);
  const [assets, setAssets] = useState<{ assetId: string, quantity: number }[]>([
    { assetId: MOCK_ASSETS[0].id, quantity: 100 }
  ]);
  const [condition, setCondition] = useState(MovementCondition.CLEAN);
  const [thaanFile, setThaanFile] = useState<File | null>(null);
  const [thaanSigned, setThaanSigned] = useState(false);

  const [errors, setErrors] = useState<string[]>([]);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'alert'} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Computed Values
  const toLocation = MOCK_LOCATIONS.find(l => l.id === destination);
  const fromLocation = MOCK_LOCATIONS.find(l => l.id === origin);
  const isCustomerDestination = toLocation?.type === LocationType.AT_CUSTOMER;
  const isTransitDestination = toLocation?.type === LocationType.IN_TRANSIT;
  const isReturningDestination = toLocation?.type === LocationType.RETURNING;

  const handleAddAsset = () => {
    setAssets([...assets, { assetId: MOCK_ASSETS[0].id, quantity: 0 }]);
  };

  const handleRemoveAsset = (index: number) => {
    setAssets(assets.filter((_, i) => i !== index));
  };

  const handleAssetChange = (index: number, field: 'assetId' | 'quantity', value: any) => {
    const newAssets = [...assets];
    newAssets[index] = { ...newAssets[index], [field]: value };
    setAssets(newAssets);
  };

  const validateMovement = () => {
    const newErrors: string[] = [];

    if ((isCustomerDestination || isTransitDestination) && !logisticsId) {
      newErrors.push("Truck and Driver information is required for Transit or Customer deliveries.");
    }

    assets.forEach(a => {
      const inv = MOCK_INVENTORY.find(i => i.location_id === origin && i.asset_id === a.assetId);
      const available = inv ? inv.quantity : 0;
      if (a.quantity > available) {
        const assetName = MOCK_ASSETS.find(asset => asset.id === a.assetId)?.name;
        newErrors.push(`Insufficient stock: Only ${available} units of ${assetName} available at ${fromLocation?.name}.`);
      }
    });

    if (isCustomerDestination && (!thaanFile || !thaanSigned)) {
      newErrors.push("Signed THAAN Slip photo and signature confirmation required for Customer delivery.");
    }

    assets.forEach(a => {
      const asset = MOCK_ASSETS.find(as => as.id === a.assetId);
      if (asset?.name.includes("Bread") && isReturningDestination) {
        newErrors.push("Penalty Trigger: QSR Crates cannot be returned to Supplier without a linked Customer THAAN reference.");
      }
    });

    setErrors(newErrors);
    return newErrors.length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateMovement()) {
      // Simulate Database Write with currentUser.id
      console.log("Saving movement with operator:", currentUser.id);

      setNotification({ 
        message: `Movement Recorded by ${currentUser.name}: ${assets.reduce((sum, a) => sum + a.quantity, 0)} items dispatched. Audit log updated.`, 
        type: 'success' 
      });
      setTimeout(() => setNotification(null), 3000);
    }
  };

  const selectedTruck = MOCK_LOGISTICS.find(l => l.id === logisticsId);
  const truckMovements = MOCK_MOVEMENTS.filter(m => m.logistics_id === logisticsId);

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-20">
      {notification && (
        <div className={`fixed bottom-8 right-8 z-50 p-4 rounded-xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right max-w-md ${notification.type === 'success' ? 'bg-emerald-600 text-white' : 'bg-rose-600 text-white'}`}>
          {notification.type === 'success' ? <CheckCircle2 size={24} /> : <AlertTriangle size={24} />}
          <p className="text-sm font-bold">{notification.message}</p>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Main Form */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="px-6 py-4 bg-slate-900 text-white flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Zap size={18} className="text-emerald-400" />
                <h3 className="font-bold text-sm uppercase tracking-widest">Movement Logger</h3>
              </div>
              <div className="flex items-center gap-2 text-[10px] bg-slate-800 px-3 py-1 rounded text-slate-300 font-bold uppercase tracking-widest border border-slate-700">
                <UserCheck size={10} className="text-emerald-400" /> Operator: {currentUser.name}
              </div>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-8">
              {/* Step 1: Origin & Destination */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <label className="block space-y-2">
                  <span className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                    <MapPin size={14} className="text-emerald-500" /> Origin Location
                  </span>
                  <select 
                    className="w-full border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500 bg-slate-50 outline-none"
                    value={origin}
                    onChange={e => setOrigin(e.target.value)}
                  >
                    {MOCK_LOCATIONS.map(l => <option key={l.id} value={l.id}>{l.name} ({l.type})</option>)}
                  </select>
                </label>
                <label className="block space-y-2">
                  <span className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                    <MapPin size={14} className="text-rose-500" /> Destination
                  </span>
                  <select 
                    className="w-full border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-emerald-500 bg-slate-50 outline-none"
                    value={destination}
                    onChange={e => setDestination(e.target.value)}
                  >
                    {MOCK_LOCATIONS.map(l => <option key={l.id} value={l.id}>{l.name} ({l.type})</option>)}
                  </select>
                </label>
              </div>

              {/* Step 2: Assets & Quantities */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <span className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                    <Package size={14} /> Assets & Batch Quantities
                  </span>
                  <button 
                    type="button" 
                    onClick={handleAddAsset}
                    className="text-[10px] font-bold text-emerald-600 flex items-center gap-1 hover:underline uppercase tracking-widest"
                  >
                    <Trash2 size={12} className="rotate-45" /> Add Row
                  </button>
                </div>
                <div className="space-y-3">
                  {assets.map((a, idx) => (
                    <div key={idx} className="flex gap-3 items-end group">
                      <div className="flex-1">
                        <select 
                          className="w-full border border-slate-200 rounded-xl p-3 text-sm bg-white outline-none focus:ring-2 focus:ring-emerald-500"
                          value={a.assetId}
                          onChange={e => handleAssetChange(idx, 'assetId', e.target.value)}
                        >
                          {MOCK_ASSETS.map(asset => <option key={asset.id} value={asset.id}>{asset.name}</option>)}
                        </select>
                      </div>
                      <div className="w-32">
                        <input 
                          type="number" 
                          placeholder="Qty"
                          className="w-full border border-slate-200 rounded-xl p-3 text-sm bg-white outline-none focus:ring-2 focus:ring-emerald-500"
                          value={a.quantity || ''}
                          onChange={e => handleAssetChange(idx, 'quantity', parseInt(e.target.value) || 0)}
                        />
                      </div>
                      {assets.length > 1 && (
                        <button 
                          type="button" 
                          onClick={() => handleRemoveAsset(idx)}
                          className="p-3 text-slate-300 hover:text-rose-500 transition-colors"
                        >
                          <X size={18} />
                        </button>
                      )}
                    </div>
                  ))}
