      case UserRole.ADMIN:
        return true; 

      case UserRole.MANAGER:
        if (contextBranchId && contextBranchId !== currentUser.branch_id) return false;
        if (permission === 'MANAGE_FEES' || permission === 'MANAGE_USERS' || permission === 'VIEW_AUDIT_LOGS') return false;
        return true;

      case UserRole.STAFF:
        if (['WRITE_MOVEMENTS', 'VERIFY_RECEIPTS', 'MANAGE_LOSSES', 'VIEW_DASHBOARD'].includes(permission)) return true;
        return false;

      case UserRole.EXECUTIVE:
        if (['VIEW_DASHBOARD', 'VIEW_SETTLEMENT'].includes(permission)) return true;
        return false;

      default:
        return false;
    }
