                />
              </label>
            </div>
          </div>

          <div className="bg-slate-900 rounded-3xl p-10 text-white flex flex-col justify-center items-center text-center shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10">
               <Database size={200} />
            </div>
            <Zap className="text-emerald-400 mb-6 relative z-10" size={56} />
            <h4 className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] mb-2 relative z-10">Accrued Liability</h4>
            <div className="text-6xl font-black text-white mb-4 relative z-10 tracking-tighter">R {calculateSimLiability().toLocaleString()}</div>
            <div className="p-6 bg-slate-800 rounded-2xl border border-slate-700 mt-6 max-w-sm relative z-10">
              <p className="text-xs text-slate-400 leading-relaxed font-bold italic">
                {simAssetType === 'Supermarket' 
                  ? (simCondition === 'Damaged' && !simClaimReceived 
                      ? "Disputed Timer Active: Accruing daily rental fees until Supplier verifies damage responsibility." 
                      : simThaan 
                        ? "Success: Liability transferred. Rental timer hard-stopped." 
                        : "Liability running: Continuous daily accrual.")
                  : (simThaan ? "Issue fee reversed/credited." : "One-time issue fee applied.")}
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

