// Define interface for props
interface FinancialReportProps {
  branchContext?: 'Kya Sands' | 'Durban' | 'Consolidated';
}

const FinancialReport: React.FC<FinancialReportProps> = ({ branchContext }) => {
  // Use branchContext to set initial branch if provided
  const getInitialBranch = () => {
    if (branchContext === 'Kya Sands') return 'Johannesburg Plant';
    if (branchContext === 'Durban') return 'Cape Town Depot'; // Simplified mapping for mock
    return 'Johannesburg Plant';
  };

  const [selectedBranch, setSelectedBranch] = useState<string>(getInitialBranch());

  // Filter batches owned by the selected branch
  // Logic: Owning branch is the 'Home' category location
  const branchBatches = MOCK_BATCHES.filter(batch => {
    // In a real DB, we'd look at the branch_id in the batches table or movements
    // Mocking: Assume JHB owns B-001/002, Cape Town owns B-003/004
    if (selectedBranch === 'Johannesburg Plant') return ['B-001', 'B-002'].includes(batch.id);
    return ['B-003', 'B-004'].includes(batch.id);
  });

  const formatCurrency = (val: number) => val.toLocaleString('en-ZA', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  // 1. Active Liabilities: Total daily rental fees for Supermarket crates in possession
  const branchAccruedRental = branchBatches.reduce((total, batch) => {
    const loc = MOCK_LOCATIONS.find(l => l.id === batch.current_location_id);
    const fee = MOCK_FEES.find(f => f.asset_id === batch.asset_id && f.fee_type.includes('Daily Rental') && f.effective_to === null);

    if (fee && loc && loc.type !== LocationType.AT_CUSTOMER && loc.type !== LocationType.RETURNING) {
      const ageDays = Math.floor((Date.now() - new Date(batch.created_at).getTime()) / (1000 * 60 * 60 * 24));
      return total + (batch.quantity * fee.amount_zar * ageDays);
    }
    return total;
  }, 0);

  // 2. Uncredited Issue Fees: QSR crates without signed THAAN
  const branchUncreditedIssueFees = branchBatches.reduce((total, batch) => {
    const fee = MOCK_FEES.find(f => f.asset_id === batch.asset_id && f.fee_type.includes('Issue Fee') && f.effective_to === null);
    const thaan = MOCK_THAANS.find(t => t.batch_id === batch.id && t.is_signed);

    if (fee && !thaan) {
      return total + (batch.quantity * fee.amount_zar);
    }
    return total;
  }, 0);

  // 3. Asset Count for Custody
  const totalAssetsInCustody = branchBatches.reduce((sum, b) => sum + b.quantity, 0);

  // 4. Monthly Loss Report (Mocked for the branch)
  const monthlyLossQty = selectedBranch === 'Johannesburg Plant' ? 12 : 5;
  const monthlyLossValue = monthlyLossQty * 150.00; // Weighted avg cost

  // Location Breakdown for Branch Assets
  const locationBreakdown = branchBatches.reduce((acc: any, b) => {
    const loc = MOCK_LOCATIONS.find(l => l.id === b.current_location_id);
    const locName = loc?.name || 'Unknown';
    acc[locName] = (acc[locName] || 0) + b.quantity;
    return acc;
  }, {});

  return (
    <div className="space-y-8 pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
        <div>
          <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <Building2 className="text-emerald-600" size={24} />
            Branch Health: {selectedBranch}
          </h3>
          <p className="text-sm text-slate-500 mt-1 uppercase tracking-widest font-bold text-[10px]">Financial Reconciliation • ZAR</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <select 
              className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
              value={selectedBranch}
              onChange={(e) => setSelectedBranch(e.target.value)}
            >
              <option value="Johannesburg Plant">JHB Plant (Kya Sands)</option>
              <option value="Cape Town Cold Storage">CT Depot (Epping)</option>
            </select>
          </div>
          <button className="p-2.5 bg-slate-900 text-white rounded-xl hover:bg-slate-800 transition-all">
            <Download size={18} />
          </button>
        </div>
      </div>

      {/* KPI Row */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
        <KPICard 
          title="Assets in Custody" 
          value={totalAssetsInCustody.toLocaleString()} 
          desc="Total Crates/Pallets Held" 
          status="info"
          icon={<Package size={24} />}
        />
        <KPICard 
          title="Accrued Rental" 
          value={`R ${formatCurrency(branchAccruedRental)}`} 
          desc="Current Possession Exposure" 
          status="danger"
          icon={<Calculator size={24} />}
        />
        <KPICard 
          title="Uncredited Issue Fees" 
          value={`R ${formatCurrency(branchUncreditedIssueFees)}`} 
          desc="QSR Outstanding PODs" 
          status="warning"
          icon={<TrendingUp size={24} />}
        />
        <KPICard 
          title="Monthly Losses" 
          value={`R ${formatCurrency(monthlyLossValue)}`} 
          desc={`${monthlyLossQty} Assets Written Off`} 
          status="critical"
          icon={<Skull size={24} />}
        />
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        {/* Location Breakdown List */}
        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="px-6 py-4 bg-slate-50 border-b border-slate-100 flex items-center justify-between">
            <h4 className="font-bold text-slate-800 text-sm flex items-center gap-2">
              <MapPin size={18} className="text-rose-500" />
              Real-Time Distribution
            </h4>
          </div>
          <div className="p-6 space-y-4">
            {Object.entries(locationBreakdown).map(([locName, qty]: any) => {
              const loc = MOCK_LOCATIONS.find(l => l.name === locName);
              return (
                <div key={locName} className="flex items-center justify-between p-4 bg-slate-50 rounded-xl border border-slate-100 group hover:border-emerald-200 transition-colors">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 bg-white rounded-lg border border-slate-200 flex items-center justify-center text-slate-400 font-bold text-[10px]">
                      {loc?.type.charAt(0)}
                    </div>
                    <div>
                      <p className="text-xs font-bold text-slate-800">{locName}</p>
                      <p className="text-[10px] text-slate-400 uppercase font-bold">{loc?.type}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-black text-slate-800">{qty.toLocaleString()}</p>
                    <p className="text-[10px] text-slate-400 font-bold">Units</p>
                  </div>
                </div>
              );
            })}
            {Object.keys(locationBreakdown).length === 0 && (
              <div className="py-12 text-center">
                 <p className="text-xs text-slate-400 italic">No assets currently tracked under this branch</p>
              </div>
            )}
          </div>
        </div>

        {/* Branch Aging & Loss Summary */}
        <div className="xl:col-span-2 space-y-8">
           <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
              <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between">
                 <h4 className="font-bold text-slate-800 text-sm">Branch Aging Analysis</h4>
                 <div className="flex gap-2">
                    <span className="bg-rose-100 text-rose-700 px-2 py-0.5 rounded text-[10px] font-bold">90d+ CRITICAL</span>
                 </div>
              </div>
              <div className="p-6 overflow-x-auto">
                 <table className="w-full text-left text-xs">
                    <thead>
                      <tr className="text-slate-400 uppercase tracking-tighter border-b border-slate-100">
                        <th className="pb-3 font-bold">Batch ID</th>
                        <th className="pb-3 font-bold">Asset</th>
                        <th className="pb-3 font-bold">Status</th>
                        <th className="pb-3 font-bold">Age</th>
                        <th className="pb-3 text-right font-bold">Exposure (ZAR)</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                       {branchBatches.map(b => {
                         const age = Math.floor((Date.now() - new Date(b.created_at).getTime()) / (1000 * 60 * 60 * 24));
                         const asset = MOCK_ASSETS.find(a => a.id === b.asset_id);
                         const fee = MOCK_FEES.find(f => f.asset_id === b.asset_id && f.effective_to === null);
                         const cost = age * (fee?.amount_zar || 0) * b.quantity;
                         return (
                           <tr key={b.id} className="hover:bg-slate-50 transition-colors">
                              <td className="py-4 font-bold text-slate-800">#{b.id}</td>
                              <td className="py-4 text-slate-500">{asset?.name}</td>
                              <td className="py-4">
                                <span className="text-[10px] font-bold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded uppercase">{b.status}</span>
                              </td>
                              <td className="py-4">
                                <span className={`font-bold ${age > 60 ? 'text-rose-600' : 'text-slate-600'}`}>{age} Days</span>
                              </td>
                              <td className="py-4 text-right font-bold text-slate-800">R {formatCurrency(cost)}</td>
                           </tr>
                         );
                       })}
                    </tbody>
                 </table>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

