  Award,
  BarChart,
  HandCoins,
  Receipt,
  UserCircle,
  ShieldCheck,
  Building2
} from 'lucide-react';
import DashboardView from './components/DashboardView';
import SchemaView from './components/SchemaView';
import BatchTracker from './components/BatchTracker';
import AssetList from './components/AssetList';
import ClaimsManager from './components/ClaimsManager';
import LogisticsOps from './components/LogisticsOps';
import InventoryDashboard from './components/InventoryDashboard';
import FinancialReport from './components/FinancialReport';
import LossRecorder from './components/LossRecorder';
import ExecutiveReport from './components/ExecutiveReport';
import SupplierRecon from './components/SupplierRecon';
import SupplierSettlementReport from './components/SupplierSettlementReport';
import { UserRole, User, Permission } from './types';

enum NavItem {
  DASHBOARD = 'dashboard',
  INVENTORY = 'inventory',
  EXECUTIVE = 'executive',
  FINANCIALS = 'financials',
  SETTLEMENT = 'settlement',
  ASSETS = 'assets',
  TRACKER = 'tracker',
  LOGISTICS = 'logistics',
  LOSSES = 'losses',
  SUPPLIER_RECON = 'supplier-recon',
  CLAIMS = 'claims',
  SCHEMA = 'schema'
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<NavItem>(NavItem.DASHBOARD);

  // 1. RBAC State - Current User
  const [currentUser, setCurrentUser] = useState<User>({
    id: 'U-001',
    name: 'John Dlamini',
    role: UserRole.ADMIN,
    branch_id: 'LOC-JHB-01'
  });

  // 2. Dashboard Branch Context Switcher (For Executives)
  const [selectedBranchFilter, setSelectedBranchFilter] = useState<'Kya Sands' | 'Durban' | 'Consolidated'>('Consolidated');

  const [isRoleModalOpen, setIsRoleModalOpen] = useState(false);

  // RBAC Middleware Logic
  const canAccess = (permission: Permission, contextBranchId?: string): boolean => {
    const role = currentUser.role;
    if (role === UserRole.ADMIN) return true;
    if (role === UserRole.MANAGER) {
      if (contextBranchId && contextBranchId !== currentUser.branch_id) return false;
      if (permission === 'MANAGE_FEES' || permission === 'MANAGE_USERS') return false;
      return true;
    }
    if (role === UserRole.STAFF) {
      return ['WRITE_MOVEMENTS', 'MANAGE_LOSSES', 'VIEW_DASHBOARD'].includes(permission);
    }
    if (role === UserRole.EXECUTIVE) {
      return ['VIEW_DASHBOARD', 'VIEW_SETTLEMENT'].includes(permission);
    }
    return false;
  };

  const navPermissions: Record<NavItem, Permission> = {
    [NavItem.DASHBOARD]: 'VIEW_DASHBOARD',
    [NavItem.INVENTORY]: 'VIEW_DASHBOARD',
    [NavItem.EXECUTIVE]: 'VIEW_DASHBOARD',
    [NavItem.FINANCIALS]: 'VIEW_DASHBOARD',
    [NavItem.SETTLEMENT]: 'VIEW_SETTLEMENT',
    [NavItem.ASSETS]: 'VIEW_DASHBOARD',
    [NavItem.TRACKER]: 'VIEW_DASHBOARD',
    [NavItem.LOGISTICS]: 'WRITE_MOVEMENTS',
    [NavItem.LOSSES]: 'MANAGE_LOSSES',
    [NavItem.SUPPLIER_RECON]: 'VIEW_SETTLEMENT',
    [NavItem.CLAIMS]: 'APPROVE_CLAIMS',
    [NavItem.SCHEMA]: 'VIEW_DASHBOARD',
  };

  const renderContent = () => {
    const permission = navPermissions[activeTab];
    if (!canAccess(permission)) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400">
           <ShieldCheck size={64} className="mb-4 opacity-20" />
           <h3 className="text-xl font-bold text-slate-800">Access Denied</h3>
           <p className="text-sm">Permissions required for {activeTab}.</p>
        </div>
      );
    }

    // Refresh context based on branch filter
    switch (activeTab) {
      // Fixed: DashboardView requires currentUser prop and added branchContext support
      case NavItem.DASHBOARD: return <DashboardView currentUser={currentUser} branchContext={selectedBranchFilter} />;
      case NavItem.INVENTORY: return <InventoryDashboard />;
      case NavItem.EXECUTIVE: return <ExecutiveReport />;
      // Fixed: FinancialReport updated to accept branchContext prop
      case NavItem.FINANCIALS: return <FinancialReport branchContext={selectedBranchFilter} />;
      case NavItem.SETTLEMENT: return <SupplierSettlementReport isAdmin={currentUser.role === UserRole.ADMIN} />;
      case NavItem.ASSETS: return <AssetList isAdmin={currentUser.role === UserRole.ADMIN} />;
      case NavItem.TRACKER: return <BatchTracker />;
      case NavItem.LOGISTICS: return <LogisticsOps currentUser={currentUser} />;
      case NavItem.LOSSES: return <LossRecorder currentUser={currentUser} />;
      case NavItem.SUPPLIER_RECON: return <SupplierRecon />;
      case NavItem.CLAIMS: return <ClaimsManager isManager={currentUser.role === UserRole.MANAGER || currentUser.role === UserRole.ADMIN} />;
      case NavItem.SCHEMA: return <SchemaView />;
