import { createClient } from '@supabase/supabase-js';
import { User, UserRole } from './types';

// Configuration for Supabase Backend
// These values are typically injected via environment variables in a production build
const SUPABASE_URL = (process.env as any).SUPABASE_URL || 'https://your-project-id.supabase.co';
const SUPABASE_ANON_KEY = (process.env as any).SUPABASE_ANON_KEY || 'your-anon-key';

/**
 * Single Supabase Instance
 * This singleton is imported across the application to handle all DB and Auth interactions.
 * It ensures a single source of truth for the session and connection pool.
 */
export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

/**
 * Helper to map Supabase User metadata to our application's User type.
 * This ensures that 'User Roles' (Admin, Manager, etc.) are respected throughout the UI.
 */
export const mapSupabaseUser = (supabaseUser: any): User | null => {
  if (!supabaseUser) return null;

  const metadata = supabaseUser.user_metadata || {};

  return {
    id: supabaseUser.id,
    name: metadata.full_name || supabaseUser.email?.split('@')[0] || 'Unknown User',
    // Fallback to STAFF role if no role is defined in metadata
    role: (metadata.role as UserRole) || UserRole.STAFF,
    // Branch context from metadata
    branch_id: metadata.branch_id || 'LOC-JHB-01'
  };
};

import React, { useState, useEffect } from 'react';
import { 
  Package, 
