enum NavItem {
  DASHBOARD = 'dashboard',
  INVENTORY = 'inventory',
  EXECUTIVE = 'executive',
  FINANCIALS = 'financials',
  SETTLEMENT = 'settlement',
  ASSETS = 'assets',
  TRACKER = 'tracker',
  LOGISTICS = 'logistics',
  LOSSES = 'losses',
  SUPPLIER_RECON = 'supplier-recon',
  CLAIMS = 'claims',
  SCHEMA = 'schema',
  USERS = 'users'
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<NavItem>(NavItem.DASHBOARD);
  const [isLoading, setIsLoading] = useState(true);

  // 1. Auth State - Managed via Supabase
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // 2. Dashboard Branch Context Switcher (For Executives)
  const [selectedBranchFilter, setSelectedBranchFilter] = useState<'Kya Sands' | 'Durban' | 'Consolidated'>('Consolidated');
  const [isRoleModalOpen, setIsRoleModalOpen] = useState(false);

  // Supabase Auth Integration Hook
  useEffect(() => {
    // Check for existing session on mount
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session) {
        setCurrentUser(mapSupabaseUser(session.user));
      }
      setIsLoading(false);
    });

    // Listen for auth changes (Login, Logout, Metadata updates)
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session) {
        setCurrentUser(mapSupabaseUser(session.user));
      } else {
        setCurrentUser(null);
      }
      setIsLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const handleMockLogin = async (role: UserRole) => {
    // In a real app, this would use supabase.auth.signInWithPassword()
    // For this demonstration, we simulate metadata retrieval
    setIsLoading(true);
    setCurrentUser({
      id: 'U-MOCK',
      name: 'Simulated User',
      role: role,
      branch_id: 'LOC-JHB-01'
    });
    setIsLoading(false);
  };

  // RBAC Middleware Logic
  const canAccess = (permission: Permission, contextBranchId?: string): boolean => {
    if (!currentUser) return false;
    const role = currentUser.role;
    if (role === UserRole.ADMIN) return true;
    if (role === UserRole.MANAGER) {
      if (contextBranchId && contextBranchId !== currentUser.branch_id) return false;
      if (permission === 'MANAGE_FEES' || permission === 'MANAGE_USERS') return false;
      return true;
    }
    if (role === UserRole.STAFF) {
      return ['WRITE_MOVEMENTS', 'MANAGE_LOSSES', 'VIEW_DASHBOARD'].includes(permission);
    }
    if (role === UserRole.EXECUTIVE) {
      return ['VIEW_DASHBOARD', 'VIEW_SETTLEMENT'].includes(permission);
    }
    return false;
  };

  const navPermissions: Record<NavItem, Permission> = {
    [NavItem.DASHBOARD]: 'VIEW_DASHBOARD',
    [NavItem.INVENTORY]: 'VIEW_DASHBOARD',
    [NavItem.EXECUTIVE]: 'VIEW_DASHBOARD',
    [NavItem.FINANCIALS]: 'VIEW_DASHBOARD',
    [NavItem.SETTLEMENT]: 'VIEW_SETTLEMENT',
    [NavItem.ASSETS]: 'VIEW_DASHBOARD',
    [NavItem.TRACKER]: 'VIEW_DASHBOARD',
    [NavItem.LOGISTICS]: 'WRITE_MOVEMENTS',
    [NavItem.LOSSES]: 'MANAGE_LOSSES',
    [NavItem.SUPPLIER_RECON]: 'VIEW_SETTLEMENT',
    [NavItem.CLAIMS]: 'APPROVE_CLAIMS',
    [NavItem.SCHEMA]: 'VIEW_DASHBOARD',
    [NavItem.USERS]: 'MANAGE_USERS'
  };

  const renderContent = () => {
    if (!currentUser) return null;

    const permission = navPermissions[activeTab];
    if (!canAccess(permission)) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400">
           <ShieldCheck size={64} className="mb-4 opacity-20" />
           <h3 className="text-xl font-bold text-slate-800">Access Denied</h3>
           <p className="text-sm">Permissions required for {activeTab}.</p>
        </div>
      );
    }

    switch (activeTab) {
      case NavItem.DASHBOARD: return <DashboardView currentUser={currentUser} branchContext={selectedBranchFilter} />;
      case NavItem.INVENTORY: return <InventoryDashboard />;
      case NavItem.EXECUTIVE: return <ExecutiveReport />;
      case NavItem.FINANCIALS: return <FinancialReport branchContext={selectedBranchFilter} />;
      case NavItem.SETTLEMENT: return <SupplierSettlementReport isAdmin={currentUser.role === UserRole.ADMIN} />;
      case NavItem.ASSETS: return <AssetList isAdmin={currentUser.role === UserRole.ADMIN} />;
      case NavItem.TRACKER: return <BatchTracker />;
      case NavItem.LOGISTICS: return <LogisticsOps currentUser={currentUser} />;
      case NavItem.LOSSES: return <LossRecorder currentUser={currentUser} />;
      case NavItem.SUPPLIER_RECON: return <SupplierRecon />;
      case NavItem.CLAIMS: return <ClaimsManager isManager={currentUser.role === UserRole.MANAGER || currentUser.role === UserRole.ADMIN} />;
      case NavItem.SCHEMA: return <SchemaView />;
      case NavItem.USERS: return <UserManagement />;
      default: return <DashboardView currentUser={currentUser} />;
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center">
        <div className="text-center space-y-4">
          <div className="w-16 h-16 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
          <p className="text-amber-500 font-black uppercase tracking-widest text-xs">Initializing Secure Session...</p>
        </div>
      </div>
    );
  }

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden">
          <div className="p-8 bg-slate-900 text-white text-center">
            <div className="w-16 h-16 bg-amber-500 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl">
              <Package size={32} />
            </div>
            <h1 className="text-2xl font-black">SHUKU Tracking</h1>
            <p className="text-amber-400 text-[10px] font-bold uppercase tracking-widest">Enterprise Access Terminal</p>
          </div>
          <div className="p-8 space-y-6">
            <div className="space-y-2">
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest text-center">Supabase RBAC Simulation</p>
              <div className="grid grid-cols-1 gap-3">
                {Object.values(UserRole).map(role => (
                  <button 
                    key={role}
                    onClick={() => handleMockLogin(role)}
                    className="w-full py-3 bg-slate-50 hover:bg-slate-100 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 transition-all flex items-center justify-center gap-2"
                  >
                    <LogIn size={16} /> Login as {role}
                  </button>
                ))}
              </div>
            </div>
            <p className="text-[10px] text-slate-400 text-center leading-relaxed italic">
              * This terminal uses Supabase Auth to manage user identities and mapped roles. 
              Permissions are strictly enforced based on the User Profile metadata.
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-slate-50">
      <aside className="w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col fixed h-full z-10 shadow-2xl">
        <div className="p-6 flex items-center gap-3 border-b border-slate-800">
          <div className="bg-amber-500 p-2 rounded-lg"><Package className="text-white w-6 h-6" /></div>
          <div><h1 className="font-black text-xl leading-tight">SHUKU</h1><p className="text-[10px] text-amber-400 font-bold uppercase">Lupo Bakery Pro</p></div>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-1 overflow-y-auto">
          <div className="pb-2 px-4"><span className="text-[10px] font-black text-slate-500 uppercase">Main Views</span></div>
          <SidebarButton active={activeTab === NavItem.DASHBOARD} onClick={() => setActiveTab(NavItem.DASHBOARD)} icon={<LayoutDashboard size={18} />} label="Global Dashboard" />
          <SidebarButton active={activeTab === NavItem.INVENTORY} onClick={() => setActiveTab(NavItem.INVENTORY)} icon={<Globe size={18} />} label="Live Inventory Map" />
          <SidebarButton active={activeTab === NavItem.FINANCIALS} onClick={() => setActiveTab(NavItem.FINANCIALS)} icon={<BarChart3 size={18} />} label="Financial Accrual Reports" />

          <div className="pt-4 pb-2 px-4"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Operations</span></div>
          <SidebarButton active={activeTab === NavItem.LOGISTICS} onClick={() => setActiveTab(NavItem.LOGISTICS)} icon={<ClipboardList size={18} />} label="Dispatch Ops" />
          <SidebarButton active={activeTab === NavItem.LOSSES} onClick={() => setActiveTab(NavItem.LOSSES)} icon={<Skull size={18} />} label="Write-off Tool" />
          <SidebarButton active={activeTab === NavItem.TRACKER} onClick={() => setActiveTab(NavItem.TRACKER)} icon={<History size={18} />} label="Batch Tracker" />

          <div className="pt-4 pb-2 px-4 border-t border-slate-800 mt-4"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Administration</span></div>
          <SidebarButton active={activeTab === NavItem.CLAIMS} onClick={() => setActiveTab(NavItem.CLAIMS)} icon={<AlertTriangle size={18} />} label="Claims Queue" />
          {canAccess('MANAGE_USERS') && (
            <SidebarButton active={activeTab === NavItem.USERS} onClick={() => setActiveTab(NavItem.USERS)} icon={<UsersIcon size={18} />} label="User Management" />
          )}
          <SidebarButton active={activeTab === NavItem.SCHEMA} onClick={() => setActiveTab(NavItem.SCHEMA)} icon={<Search size={18} />} label="System Arch" />
        </nav>

        <div className="p-4 bg-slate-950/50 border-t border-slate-800 relative">
          <div className="flex items-center justify-between mb-4 px-2">
            <button onClick={() => setIsRoleModalOpen(!isRoleModalOpen)} className="flex items-center gap-3 group text-left">
              <div className="w-8 h-8 rounded-full bg-amber-500 flex items-center justify-center text-xs font-black text-slate-900 group-hover:scale-110 transition-transform shadow-lg">{currentUser.name.charAt(0)}</div>
              <div className="overflow-hidden">
                <p className="text-xs font-bold truncate group-hover:text-amber-400 transition-colors">{currentUser.name}</p>
                <p className="text-[10px] text-slate-500 uppercase font-black">{currentUser.role}</p>
              </div>
            </button>
            <button onClick={handleLogout} title="Logout" className="p-2 text-slate-500 hover:text-rose-500 transition-colors">
              <LogOut size={16} />
            </button>
          </div>

          {isRoleModalOpen && (
            <div className="absolute bottom-full left-4 right-4 mb-2 bg-slate-800 rounded-xl border border-slate-700 shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-2 z-50">
              <div className="p-3 border-b border-slate-700 bg-slate-900"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Switch Identity (RBAC Test)</p></div>
              {Object.values(UserRole).map(role => (
                <button key={role} onClick={() => { setCurrentUser({...currentUser, role}); setIsRoleModalOpen(false); }} className={`w-full text-left px-4 py-2.5 text-xs font-bold hover:bg-slate-700 transition-colors ${currentUser.role === role ? 'text-amber-400 bg-slate-700/50' : 'text-slate-300'}`}>{role}</button>
              ))}
            </div>
          )}
        </div>
      </aside>

      <main className="ml-64 flex-1 flex flex-col min-h-screen">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 sticky top-0 z-20 shadow-sm">
          <h2 className="font-bold text-lg text-slate-800 capitalize tracking-tight">{activeTab.replace('-', ' ')}</h2>

          <div className="flex items-center gap-6">
            {/* Branch Switcher (Dashboard/Financials) */}
            {(currentUser.role === UserRole.EXECUTIVE || currentUser.role === UserRole.ADMIN) && (
              <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-xl border border-slate-200">
                <div className="flex items-center gap-2 px-3 py-1 text-[10px] font-black uppercase text-slate-400 border-r border-slate-200">
                  <Building2 size={14} /> Branch
                </div>
                {['Kya Sands', 'Durban', 'Consolidated'].map(branch => (
                  <button
                    key={branch}
                    onClick={() => setSelectedBranchFilter(branch as any)}
                    className={`px-3 py-1 text-[10px] font-black uppercase rounded-lg transition-all ${selectedBranchFilter === branch ? 'bg-white text-slate-900 shadow-sm ring-1 ring-slate-200/50' : 'text-slate-500 hover:text-slate-700'}`}
                  >
                    {branch}
                  </button>
                ))}
              </div>
            )}

            <div className="flex items-center gap-4">
              <div className="text-right">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{currentUser.branch_id} / SAST</p>
                <p className="text-sm font-bold text-slate-700">{new Date().toLocaleTimeString('en-ZA')}</p>
              </div>
              <div className="h-8 w-px bg-slate-200 mx-1" />
              <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-400"><UserCircle size={20} /></div>
            </div>
          </div>
        </header>

        <div className="p-8">{renderContent()}</div>
      </main>
    </div>
  );
};

const SidebarButton: React.FC<{ active: boolean, onClick: () => void, icon: React.ReactNode, label: string }> = ({ active, onClick, icon, label }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-lg transition-all duration-200 ${active ? 'bg-amber-500 text-slate-900 shadow-lg shadow-amber-900/20 translate-x-1 font-bold' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
    {icon}
    <span className="text-sm tracking-tight">{label}</span>
    {active && <ChevronRight className="ml-auto" size={12} />}
  </button>
);

export default App;

import React, { useState, useRef } from 'react';
import { Truck, MapPin, ClipboardList, CheckCircle2, AlertTriangle, ArrowRight, User, Package, Zap, Camera, FileText, Trash2, X, UserCheck } from 'lucide-react';
import { MOCK_BATCHES, MOCK_LOCATIONS, MOCK_LOGISTICS, MOCK_ASSETS, MOCK_INVENTORY, MOCK_MOVEMENTS } from '../constants';
import { MovementCondition, LocationType, AssetType, User as UserType } from '../types';
import { supabase } from '../supabase';

interface LogisticsOpsProps {
  currentUser: UserType;
}

const LogisticsOps: React.FC<LogisticsOpsProps> = ({ currentUser }) => {
  const [origin, setOrigin] = useState(MOCK_LOCATIONS[0].id);
  const [destination, setDestination] = useState(MOCK_LOCATIONS[3].id); 
  const [logisticsId, setLogisticsId] = useState(MOCK_LOGISTICS[0].id);
  const [assets, setAssets] = useState<{ assetId: string, quantity: number, batchId?: string }[]>([
    { assetId: MOCK_ASSETS[0].id, quantity: 0 }
  ]);
  const [condition, setCondition] = useState(MovementCondition.CLEAN);
  const [thaanFile, setThaanFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [errors, setErrors] = useState<string[]>([]);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'alert'} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAddAsset = () => setAssets([...assets, { assetId: MOCK_ASSETS[0].id, quantity: 0 }]);
  const handleRemoveAsset = (index: number) => setAssets(assets.filter((_, i) => i !== index));
  const handleAssetChange = (index: number, field: 'assetId' | 'quantity' | 'batchId', value: any) => {
    const newAssets = [...assets];
    newAssets[index] = { ...newAssets[index], [field]: value };
    setAssets(newAssets);
  };

  /**
   * Action: 'Capture Movement' Button Logic (Supabase Enabled)
   * 1. Validates quantities against current batch availability.
   * 2. Inserts record into movement_logs (BatchMovements).
   * 3. Updates current_location_id in movement_batches (Batches).
   */
  const handleCaptureMovement = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrors([]);

    // UI Validation
    const validationErrors: string[] = [];
    if (assets.some(a => a.quantity <= 0)) validationErrors.push("All line items must have a quantity > 0.");
    if (origin === destination) validationErrors.push("Origin and Destination cannot be the same.");

    const destType = MOCK_LOCATIONS.find(l => l.id === destination)?.type;
    if (destType === LocationType.AT_CUSTOMER && !thaanFile) {
      validationErrors.push("Customer delivery requires a THAAN Slip upload.");
    }

    if (validationErrors.length > 0) {
      setErrors(validationErrors);
      return;
    }

    setIsSubmitting(true);

    try {
      for (const item of assets) {
        // 1. Verify availability logic
        // In a real scenario, we fetch the batch from Supabase first
        const { data: batch, error: fetchError } = await supabase
          .from('Batches')
          .select('quantity, current_location_id')
          .eq('id', item.batchId || 'LB-BATCH-001') // Fallback to mock ID if not selected
          .single();

        if (fetchError || !batch) throw new Error(`Could not find Batch ${item.batchId}`);
        if (batch.quantity < item.quantity) {
          throw new Error(`Insufficient quantity in Batch ${item.batchId}. Available: ${batch.quantity}`);
        }

        // 2. Insert into movement_logs (BatchMovements)
        const { error: moveError } = await supabase
          .from('BatchMovements')
          .insert([{
            batch_id: item.batchId || 'LB-BATCH-001',
            from_location_id: origin,
            to_location_id: destination,
            logistics_id: logisticsId,
            timestamp: new Date().toISOString(),
            condition: condition,
            origin_user_id: currentUser.id
          }]);

        if (moveError) throw moveError;

        // 3. Update current_location_id in movement_batches (Batches)
        const { error: updateError } = await supabase
          .from('Batches')
          .update({ 
            current_location_id: destination,
            status: destType === LocationType.IN_TRANSIT ? 'In-Transit' : 'Success'
          })
          .eq('id', item.batchId || 'LB-BATCH-001');

        if (updateError) throw updateError;
      }

      // 4. Handle Thaan Slip Upload if present
      if (thaanFile && assets[0]?.batchId) {
        const fileExt = thaanFile.name.split('.').pop();
        const fileName = `${assets[0].batchId}-${Math.random()}.${fileExt}`;
        const filePath = `thaan-slips/${fileName}`;

        const { error: uploadError } = await supabase.storage
          .from('thaan-slips')
          .upload(filePath, thaanFile);

        if (uploadError) throw uploadError;

        const { data: publicUrlData } = supabase.storage
          .from('thaan-slips')
          .getPublicUrl(filePath);

        await supabase
          .from('ThaanSlips')
          .insert([{
            batch_id: assets[0].batchId,
            doc_url: publicUrlData.publicUrl,
            is_signed: true,
            signed_at: new Date().toISOString()
          }]);
      }

      setNotification({ message: "Manifest logged & batches updated in Supabase.", type: 'success' });
      setAssets([{ assetId: MOCK_ASSETS[0].id, quantity: 0 }]);
      setThaanFile(null);
    } catch (err: any) {
      setNotification({ message: err.message || "Failed to record movement.", type: 'alert' });
    } finally {
      setIsSubmitting(false);
      setTimeout(() => setNotification(null), 4000);
    }
  };

  const selectedTruck = MOCK_LOGISTICS.find(l => l.id === logisticsId);

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-20">
      {notification && (
        <div className={`fixed bottom-8 right-8 z-50 p-4 rounded-xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right max-w-md ${notification.type === 'success' ? 'bg-emerald-600 text-white' : 'bg-rose-600 text-white'}`}>
          {notification.type === 'success' ? <CheckCircle2 size={24} /> : <AlertTriangle size={24} />}
          <p className="text-sm font-bold">{notification.message}</p>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="px-6 py-4 bg-slate-900 text-white flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Zap size={18} className="text-emerald-400" />
                <h3 className="font-bold text-sm uppercase tracking-widest">Capture Movement</h3>
              </div>
              <span className="text-[10px] font-black uppercase text-emerald-500 bg-slate-800 px-2 py-1 rounded">Backend: Supabase PG</span>
            </div>

            <form onSubmit={handleCaptureMovement} className="p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <label className="block space-y-2">
                  <span className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                    <MapPin size={14} className="text-emerald-500" /> Origin Location
                  </span>
                  <select 
                    className="w-full border border-slate-200 rounded-xl p-3 text-sm bg-slate-50 outline-none"
                    value={origin}
                    onChange={e => setOrigin(e.target.value)}
                  >
                    {MOCK_LOCATIONS.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}
                  </select>
                </label>
                <label className="block space-y-2">
                  <span className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2">
                    <MapPin size={14} className="text-rose-500" /> Destination
                  </span>
                  <select 
                    className="w-full border border-slate-200 rounded-xl p-3 text-sm bg-slate-50 outline-none"
                    value={destination}
                    onChange={e => setDestination(e.target.value)}
                  >
                    {MOCK_LOCATIONS.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}
                  </select>
                </label>
              </div>

              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <span className="text-xs font-bold text-slate-500 uppercase">Assets & Quantities</span>
                  <button type="button" onClick={handleAddAsset} className="text-[10px] font-bold text-emerald-600 hover:underline uppercase tracking-widest">Add Row</button>
                </div>
                <div className="space-y-3">
                  {assets.map((a, idx) => (
                    <div key={idx} className="flex gap-3">
                      <select 
                        className="flex-1 border border-slate-200 rounded-xl p-3 text-sm bg-white outline-none"
                        value={a.batchId}
                        onChange={e => handleAssetChange(idx, 'batchId', e.target.value)}
                      >
                        <option value="">Select Batch Ref</option>
                        {MOCK_BATCHES.filter(b => b.current_location_id === origin).map(b => (
                          <option key={b.id} value={b.id}>{b.id} ({b.quantity} available)</option>
                        ))}
                      </select>
                      <input 
                        type="number" 
                        placeholder="Qty"
                        className="w-32 border border-slate-200 rounded-xl p-3 text-sm bg-white outline-none"
                        value={a.quantity || ''}
                        onChange={e => handleAssetChange(idx, 'quantity', parseInt(e.target.value) || 0)}
                      />
                      {assets.length > 1 && (
                        <button type="button" onClick={() => handleRemoveAsset(idx)} className="p-3 text-slate-300 hover:text-rose-500">
                          <X size={18} />
                        </button>
                      )}
                    </div>
                  ))}
                </div>
              </div>

              <div className="p-6 bg-blue-50/50 rounded-2xl border border-blue-100 space-y-4">
                <h4 className="text-xs font-bold text-blue-600 uppercase flex items-center gap-2"><Truck size={14} /> Logistics Details</h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <label className="block space-y-2">
                    <span className="text-[10px] font-bold text-slate-400 uppercase">Truck & Driver</span>
                    <select 
                      className="w-full border border-slate-200 rounded-xl p-3 text-sm bg-white"
                      value={logisticsId}
                      onChange={e => setLogisticsId(e.target.value)}
                    >
                      {MOCK_LOGISTICS.map(l => <option key={l.id} value={l.id}>{l.truck_plate} - {l.driver_name}</option>)}
                    </select>
                  </label>
                </div>
              </div>

              <div className="space-y-4 pt-4 border-t border-slate-100">
                <div className="flex flex-col md:flex-row gap-8">
                  <div className="flex-1 space-y-4">
                    <span className="text-xs font-bold text-slate-500 uppercase">Condition</span>
                    <div className="grid grid-cols-3 gap-2">
                      {[MovementCondition.CLEAN, MovementCondition.DIRTY, MovementCondition.DAMAGED].map(cond => (
                        <button
                          key={cond}
                          type="button"
                          onClick={() => setCondition(cond)}
                          className={`py-2 px-1 rounded-lg text-[10px] font-bold uppercase border-2 ${condition === cond ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'bg-white border-slate-100 text-slate-400'}`}
                        >
                          {cond}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="flex-1 space-y-4">
                    <span className="text-xs font-bold text-slate-500 uppercase">Upload THAAN Slip</span>
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={e => setThaanFile(e.target.files?.[0] || null)} />
                    <button 
                      type="button"
                      onClick={() => fileInputRef.current?.click()}
                      className={`w-full py-3 rounded-xl border-2 border-dashed flex items-center justify-center gap-2 text-xs font-bold ${thaanFile ? 'border-emerald-200 bg-emerald-50 text-emerald-700' : 'border-slate-200 text-slate-500'}`}
                    >
                      <Camera size={16} /> {thaanFile ? thaanFile.name : 'Choose Image'}
                    </button>
                  </div>
                </div>
              </div>

              {errors.length > 0 && (
                <div className="p-4 bg-rose-50 rounded-xl border border-rose-100 space-y-1">
                  {errors.map((err, i) => (
                    <div key={i} className="flex items-center gap-2 text-xs font-medium text-rose-600"><AlertTriangle size={12} /> {err}</div>
                  ))}
                </div>
              )}

              <button 
                type="submit" 
                disabled={isSubmitting}
                className="w-full bg-slate-900 hover:bg-slate-800 text-white font-black py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3"
              >
                {isSubmitting ? 'Syncing to Supabase...' : 'RECORD MOVEMENT'}
              </button>
            </form>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
            <h3 className="font-bold text-slate-800 text-xs uppercase tracking-widest mb-4">Unit Summary</h3>
            <div className="flex items-center gap-4 mb-6">
              <div className="w-12 h-12 bg-slate-900 rounded-xl flex items-center justify-center text-white shadow-lg"><Truck size={24} /></div>
              <div>
                <p className="text-lg font-bold text-slate-800 leading-none mb-1">{selectedTruck?.truck_plate || 'Unassigned'}</p>
                <p className="text-xs text-slate-500">{selectedTruck?.driver_name || 'No Driver'}</p>
              </div>
            </div>
            <div className="p-4 bg-emerald-50 rounded-xl border border-emerald-100">
              <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Audit Context</p>
              <p className="text-xs text-emerald-800 mt-1 font-medium italic">Logged by: {currentUser.name}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LogisticsOps;

import React, { useState, useRef } from 'react';
import { MOCK_BATCHES, MOCK_MOVEMENTS, MOCK_LOCATIONS, MOCK_LOGISTICS, MOCK_FEES, MOCK_ASSETS, MOCK_THAANS } from '../constants';
import { Package, Truck, Clock, MapPin, CheckCircle2, AlertCircle, FileText, Zap, History, Camera, UploadCloud, XCircle } from 'lucide-react';
import { FeeType, ThaanSlip } from '../types';
import { supabase } from '../supabase';

const BatchTracker: React.FC = () => {
  const [batches, setBatches] = useState(MOCK_BATCHES);
  const [thaans, setThaans] = useState<ThaanSlip[]>(MOCK_THAANS);
  const [selectedBatchId, setSelectedBatchId] = useState(batches[0].id);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadError, setUploadError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const currentBatch = batches.find(b => b.id === selectedBatchId)!;
  const movements = MOCK_MOVEMENTS.filter(m => m.batch_id === selectedBatchId);
  const asset = MOCK_ASSETS.find(a => a.id === currentBatch.asset_id)!;
  const thaan = thaans.find(t => t.batch_id === selectedBatchId);

  /**
   * Action: 'Upload THAAN Slip' Logic (Supabase Storage)
   * 1. Uploads binary to 'thaan-slips' bucket.
   * 2. Saves public URL to ThaanSlips table.
   * 3. Toggles thaan_slip_signed (mapped as is_signed) to TRUE.
   */
  const handleUploadThaan = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setUploadError(null);

    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${selectedBatchId}-${Math.random()}.${fileExt}`;
      const filePath = `thaan-slips/${fileName}`;

      // 1. Storage Upload
      const { error: storageError } = await supabase.storage
        .from('thaan-slips')
        .upload(filePath, file);

      if (storageError) throw storageError;

      // 2. Get Public URL
      const { data: { publicUrl } } = supabase.storage
        .from('thaan-slips')
        .getPublicUrl(filePath);

      // 3. Database Sync
      const { data: newThaanRecord, error: dbError } = await supabase
        .from('ThaanSlips')
        .insert([{
          batch_id: selectedBatchId,
          doc_url: publicUrl,
          is_signed: true,
          signed_at: new Date().toISOString()
        }])
        .select()
        .single();

      if (dbError) throw dbError;

      // 4. Local State Refresh
      setThaans(prev => {
        const filtered = prev.filter(t => t.batch_id !== selectedBatchId);
        return [...filtered, newThaanRecord as ThaanSlip];
      });

      setBatches(prev => prev.map(b => b.id === selectedBatchId ? { ...b, status: 'Success' } : b));

    } catch (err: any) {
      setUploadError(err.message || "Failed to upload THAAN slip.");
    } finally {
      setIsUploading(false);
    }
  };

  const getFeeForBatch = () => {
    return MOCK_FEES.find(f => 
      f.asset_id === currentBatch.asset_id &&
      new Date(currentBatch.created_at) >= new Date(f.effective_from) &&
      (!f.effective_to || new Date(currentBatch.created_at) <= new Date(f.effective_to))
    );
  };

  const applicableFee = getFeeForBatch();
  const formatCurrency = (val: number) => val.toLocaleString('en-ZA', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  return (
    <div className="space-y-8">
      <div className="flex flex-wrap gap-4 items-center">
        {batches.map(b => (
          <button 
            key={b.id}
            onClick={() => setSelectedBatchId(b.id)}
            className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${
              selectedBatchId === b.id 
                ? 'bg-slate-900 text-white ring-4 ring-slate-200' 
                : 'bg-white border border-slate-200 text-slate-500 hover:bg-slate-50'
            }`}
          >
            {b.id} ({b.status})
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-xl border border-slate-200 p-8 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-8 flex items-center gap-2">
              <History size={20} className="text-emerald-500" />
              Movement History
            </h3>

            <div className="relative pl-8 border-l-2 border-slate-100 space-y-12">
              {movements.map((mv, idx) => {
                const from = MOCK_LOCATIONS.find(l => l.id === mv.from_location_id);
                const to = MOCK_LOCATIONS.find(l => l.id === mv.to_location_id);
                const logs = mv.logistics_id ? MOCK_LOGISTICS.find(l => l.id === mv.logistics_id) : null;

                return (
                  <div key={mv.id} className="relative">
                    <div className="absolute -left-[41px] top-0 w-4 h-4 rounded-full bg-emerald-500 ring-4 ring-emerald-50" />
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                      <div>
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{new Date(mv.timestamp).toLocaleString('en-ZA')}</p>
                        <h4 className="font-bold text-slate-800 text-lg mt-1">{from?.name} &rarr; {to?.name}</h4>
                        <div className="flex gap-2 mt-2">
                          <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-tight ${mv.condition === 'Clean' ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'}`}>{mv.condition}</span>
                          {logs && <span className="bg-blue-100 text-blue-700 px-2 py-0.5 rounded text-[10px] font-bold flex items-center gap-1"><Truck size={10} /> {logs.truck_plate}</span>}
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}

              {(currentBatch.status === 'Success' || thaan?.is_signed) && (
                <div className="relative">
                  <div className="absolute -left-[41px] top-0 w-4 h-4 rounded-full bg-emerald-600 ring-4 ring-emerald-100 flex items-center justify-center"><CheckCircle2 size={10} className="text-white" /></div>
                  <div>
                    <h4 className="font-bold text-emerald-600">Finalized - Delivery Confirmed</h4>
                    <p className="text-sm text-slate-500">All liability transferred to customer location.</p>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-emerald-900 text-white rounded-xl p-6 shadow-xl relative overflow-hidden">
             <div className="absolute top-0 right-0 p-4 opacity-10"><Zap size={100} /></div>
             <h3 className="text-sm font-bold uppercase tracking-widest text-emerald-400 mb-4">Fee Analysis</h3>
             <div className="space-y-4 relative z-10">
               <div className="flex justify-between border-b border-emerald-800 pb-2"><span className="text-emerald-100 text-xs">Asset</span><span className="font-bold">{asset.name}</span></div>
               <div className="flex justify-between border-b border-emerald-800 pb-2"><span className="text-emerald-100 text-xs">Rate</span><span className="font-bold">R {applicableFee?.amount_zar.toFixed(2)}</span></div>
               <div className="flex justify-between items-end">
                 <div>
                    <p className="text-[10px] text-emerald-400 font-bold uppercase">Total Accrued</p>
                    <p className="text-2xl font-bold">R {formatCurrency(currentBatch.quantity * (applicableFee?.amount_zar || 0))}</p>
                 </div>
               </div>
             </div>
          </div>

          <div className="bg-white rounded-xl border border-slate-200 p-6 shadow-sm">
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-bold text-slate-800 flex items-center gap-2"><FileText size={18} className="text-slate-400" /> THAAN Slip</h3>
              <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleUploadThaan} />
            </div>

            {uploadError && (
              <div className="p-3 mb-4 bg-rose-50 text-rose-600 text-xs font-bold rounded-lg border border-rose-100 flex items-center gap-2">
                <AlertCircle size={14} /> {uploadError}
              </div>
            )}

            {thaan ? (
              <div className="space-y-4 animate-in fade-in">
                <div className="aspect-[4/5] bg-slate-100 rounded-lg border border-slate-200 overflow-hidden relative group shadow-inner">
                  <img src={thaan.doc_url} alt="THAAN Slip" className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <button onClick={() => fileInputRef.current?.click()} className="bg-white text-slate-900 px-4 py-2 rounded-lg text-xs font-bold shadow-lg">Replace Image</button>
                  </div>
                </div>
                <div className="p-3 rounded-lg flex items-center gap-3 bg-emerald-50 text-emerald-700 border border-emerald-100">
                  <CheckCircle2 size={18} />
                  <span className="text-xs font-bold">Verified on {new Date(thaan.signed_at!).toLocaleDateString()}</span>
                </div>
              </div>
            ) : (
              <button 
                onClick={() => fileInputRef.current?.click()}
                disabled={isUploading}
                className="w-full py-12 text-center bg-slate-50 rounded-lg border-2 border-dashed border-slate-200 hover:bg-slate-100 hover:border-emerald-300 transition-all group"
              >
                <UploadCloud className="mx-auto text-slate-300 group-hover:text-emerald-500 mb-2" size={32} />
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{isUploading ? 'Uploading to Supabase...' : 'Upload Signed Slip'}</p>
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default BatchTracker;

import React, { useMemo, useState, useEffect } from 'react';
import { Truck, Package, AlertTriangle, TrendingUp, ArrowUpRight, ArrowDownRight, Clock, ShieldAlert, Calendar, User, History, UserCheck, Skull, MapPin, Loader2 } from 'lucide-react';
import { MOCK_BATCHES, MOCK_CLAIMS, MOCK_LOCATIONS, MOCK_MOVEMENTS, MOCK_LOGISTICS, MOCK_ASSETS, MOCK_LOSSES, MOCK_USERS } from '../constants';
import { LocationType, UserRole, User as UserType, Batch, AssetLoss } from '../types';
import { supabase } from '../supabase';

interface DashboardViewProps {
  currentUser: UserType;
  branchContext?: 'Kya Sands' | 'Durban' | 'Consolidated';
}

const DashboardView: React.FC<DashboardViewProps> = ({ currentUser, branchContext = 'Consolidated' }) => {
  const [dbBatches, setDbBatches] = useState<Batch[]>([]);
  const [dbLosses, setDbLosses] = useState<AssetLoss[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Supabase Real-time Dashboard Fetch
  useEffect(() => {
    const fetchDashboardData = async () => {
      setIsLoading(true);
      try {
        // 1. Fetch movement_batches (Batches) with branch filter
        let batchQuery = supabase.from('Batches').select('*');

        if (branchContext !== 'Consolidated') {
          const branchMapping = {
            'Kya Sands': 'LOC-JHB-01',
            'Durban': 'LOC-DBN-01'
          };
          const targetBranchId = branchMapping[branchContext as keyof typeof branchMapping];
          batchQuery = batchQuery.eq('current_location_id', targetBranchId);
        }

        const { data: batches, error: bError } = await batchQuery;
        if (bError) throw bError;
        setDbBatches(batches as Batch[] || []);

        // 2. Fetch Losses
        const { data: losses, error: lError } = await supabase.from('AssetLosses').select('*');
        if (lError) throw lError;
        setDbLosses(losses as AssetLoss[] || []);

      } catch (err) {
        console.error("Dashboard Sync Error:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchDashboardData();
  }, [branchContext]);

  // Merge DB data with MOCK for UI robustness
  const displayBatches = dbBatches.length > 0 ? dbBatches : MOCK_BATCHES;
  const displayLosses = dbLosses.length > 0 ? dbLosses : MOCK_LOSSES;

  const filteredBatches = useMemo(() => {
    if (branchContext === 'Consolidated') return displayBatches;
    const branchName = branchContext === 'Kya Sands' ? 'Kya Sands' : 'KZN';
    return displayBatches.filter(b => {
        const loc = MOCK_LOCATIONS.find(l => l.id === b.current_location_id);
        return loc?.name.includes(branchName);
    });
  }, [branchContext, displayBatches]);

  const filteredLosses = useMemo(() => {
    if (branchContext === 'Consolidated') return displayLosses;
    const branchName = branchContext === 'Kya Sands' ? 'Kya Sands' : 'KZN';
    return displayLosses.filter(l => {
        const loc = MOCK_LOCATIONS.find(loc => loc.id === l.last_known_location_id);
        return loc?.name.includes(branchName);
    });
  }, [branchContext, displayLosses]);

  const totalPallets = filteredBatches.reduce((acc, b) => b.asset_id.includes('P') ? acc + b.quantity : acc, 0);
  const estimatedUnbilledRental = filteredBatches.length * 145.20; 
  const pendingClaimsValue = MOCK_CLAIMS.filter(c => c.status === 'Lodged').reduce((acc, c) => acc + c.amount_claimed_zar, 0);

  const formatCurrency = (val: number) => val.toLocaleString('en-ZA', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-[50vh]">
        <div className="flex flex-col items-center gap-3">
          <Loader2 className="animate-spin text-amber-500" size={32} />
          <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Polling Supabase Clusters...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Manager Oversight - Accountability for Losses */}
      {(currentUser.role === UserRole.MANAGER || currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.EXECUTIVE) && (
        <div className="bg-white rounded-3xl shadow-xl shadow-slate-200 border border-slate-200 overflow-hidden ring-4 ring-slate-50 transition-all">
          <div className="px-8 py-5 bg-slate-900 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-rose-500 rounded-lg shadow-inner"><Skull size={18} className="text-white" /></div>
              <div>
                <h3 className="font-black text-xs uppercase tracking-[0.2em] text-white">Loss Accountability Matrix</h3>
                <p className="text-[10px] font-bold text-slate-400">Context: {branchContext} Branch Filter (Synced)</p>
              </div>
            </div>
            <div className="flex items-center gap-2 px-4 py-1.5 bg-slate-800 rounded-full border border-slate-700">
               <UserCheck size={14} className="text-emerald-400" />
               <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Supabase Live Query</span>
            </div>
          </div>
          <div className="p-8">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredLosses.slice(0, 3).map(loss => {
                const batch = displayBatches.find(b => b.id === loss.batch_id);
                const reporter = MOCK_USERS.find(u => u.id === loss.reported_by);
                const riskLevel = loss.lost_quantity > 20 ? 'CRITICAL' : 'MODERATE';
                const location = MOCK_LOCATIONS.find(l => l.id === loss.last_known_location_id);

                return (
                  <div key={loss.id} className={`p-6 rounded-2xl border-2 transition-all group relative overflow-hidden hover:shadow-lg ${riskLevel === 'CRITICAL' ? 'border-rose-100 bg-rose-50/30' : 'border-slate-100 bg-slate-50'}`}>
                    <div className="relative z-10">
                       <div className="flex justify-between items-start mb-4">
                         <span className={`text-[9px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest ${riskLevel === 'CRITICAL' ? 'bg-rose-600 text-white shadow-sm' : 'bg-amber-500 text-white shadow-sm'}`}>
                            {riskLevel} RISK
                         </span>
                         <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">REF: {loss.id}</span>
                       </div>

                       <p className="text-sm font-black text-slate-800 leading-tight mb-1">{loss.lost_quantity}x {MOCK_ASSETS.find(a => a.id === batch?.asset_id)?.name}</p>
                       <p className="text-[10px] text-slate-400 font-bold mb-4 flex items-center gap-1"><MapPin size={10} /> {location?.name}</p>
                       <p className="text-xs text-slate-500 line-clamp-2 italic mb-6">"{loss.notes}"</p>

                       <div className="pt-4 border-t border-slate-200 flex items-center justify-between">
                          <div className="flex items-center gap-3">
                             <div className="w-10 h-10 rounded-full bg-slate-900 flex items-center justify-center border-4 border-white shadow-lg group-hover:scale-110 transition-transform">
                                <span className="text-xs font-black text-white">{reporter?.name.charAt(0) || 'U'}</span>
                             </div>
                             <div>
                                <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">Reporter</p>
                                <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{reporter?.name || 'Supabase User'}</p>
                             </div>
                          </div>
                          <div className="text-right">
                             <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Reported</p>
                             <p className="text-[10px] font-bold text-slate-700">{new Date(loss.timestamp).toLocaleDateString()}</p>
                          </div>
                       </div>
                    </div>
                  </div>
                );
              })}
              {filteredLosses.length === 0 && (
                <div className="col-span-3 py-12 text-center bg-slate-50 rounded-2xl border-2 border-dashed border-slate-200">
                  <p className="text-sm text-slate-400 italic">No reported losses found in this context.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          label="Active Batches" 
          value={filteredBatches.length.toString()} 
          trend="+2.5%" 
          trendUp={true} 
          icon={<Package className="text-blue-500" />} 
        />
        <StatCard 
          label="In Transit" 
          value={filteredBatches.filter(b => b.status === 'In-Transit' || MOCK_LOCATIONS.find(l => l.id === b.current_location_id)?.type === LocationType.IN_TRANSIT).length.toString()} 
          trend="-4%" 
          trendUp={false} 
          icon={<Truck className="text-amber-500" />} 
        />
        <StatCard 
          label="Pending Claims" 
          value={MOCK_CLAIMS.filter(c => c.status === 'Lodged').length.toString()} 
          trend="+1" 
          trendUp={true} 
          icon={<AlertTriangle className="text-rose-500" />} 
        />
        <StatCard 
          label="Avg Turnaround" 
          value="4.2 Days" 
          trend="0.5%" 
          trendUp={true} 
          icon={<TrendingUp className="text-emerald-500" />} 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col hover:border-emerald-200 transition-colors group">
          <div className="px-6 py-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center group-hover:bg-emerald-50 transition-colors">
            <div className="flex items-center gap-2">
              <Calendar size={18} className="text-emerald-600" />
              <h3 className="font-bold text-slate-800">Branch Accrual Matrix</h3>
            </div>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Real-time ZAR</span>
          </div>
          <div className="p-6 space-y-6 flex-1 flex flex-col justify-between">
            <div className="space-y-6">
              <div className="flex justify-between items-end border-b border-slate-50 pb-4">
                <div>
                  <p className="text-xs text-slate-500 font-medium uppercase tracking-tighter">Pallets (Active)</p>
                  <p className="text-2xl font-bold text-slate-800">{totalPallets}</p>
                </div>
                <div className="text-right">
                  <p className="text-xs text-slate-500 font-medium uppercase tracking-tighter">Crates</p>
                  <p className="text-xl font-bold text-slate-800">{filteredBatches.length - totalPallets}</p>
                </div>
              </div>

              <div className="flex justify-between items-end border-b border-slate-50 pb-4">
                <div>
                  <p className="text-xs text-slate-500 font-medium uppercase tracking-tighter">Accrued Rental Liability</p>
                  <p className="text-2xl font-bold text-emerald-600">R {formatCurrency(estimatedUnbilledRental)}</p>
                </div>
                <div className="px-2 py-1 bg-emerald-50 text-emerald-600 text-[9px] font-black rounded uppercase tracking-widest animate-pulse">Running</div>
              </div>

              <div>
                <p className="text-xs text-slate-500 font-medium uppercase tracking-tighter">Pending Claim Value</p>
                <p className="text-2xl font-bold text-rose-500">R {formatCurrency(pendingClaimsValue)}</p>
                <p className="text-[9px] text-slate-400 mt-1 italic leading-tight">* Offset potential from supplier recovery</p>
              </div>
            </div>

            <button className="w-full mt-6 py-3 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
              <TrendingUp size={14} /> View Historical Drill-down
            </button>
          </div>
        </div>

        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col hover:border-blue-100 transition-colors">
          <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <div className="flex items-center gap-2">
               <History size={16} className="text-blue-500" />
               <h3 className="font-bold text-slate-800 uppercase tracking-widest text-[11px]">Branch Operations Manifest</h3>
            </div>
            <button className="text-[10px] text-blue-600 font-black uppercase tracking-widest hover:underline">View All</button>
          </div>
          <div className="divide-y divide-slate-50 overflow-y-auto max-h-[420px]">
            {filteredBatches.map((batch, i) => {
              const loc = MOCK_LOCATIONS.find(l => l.id === batch.current_location_id);
              return (
                <div key={batch.id} className="px-6 py-4 flex items-center justify-between hover:bg-slate-50 transition-colors group/row">
                  <div className="flex items-center gap-4">
                    <div className={`p-2.5 rounded-xl shadow-sm group-hover/row:scale-110 transition-transform ${batch.status === 'In-Transit' ? 'bg-amber-100 text-amber-600' : 'bg-emerald-100 text-emerald-600'}`}>
                      {batch.status === 'In-Transit' ? <Truck size={20} /> : <Package size={20} />}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="font-black text-slate-800 tracking-tight">#{batch.id}</p>
                        {batch.status === 'In-Transit' && <span className="text-[8px] font-black bg-amber-500 text-white px-1.5 py-0.5 rounded uppercase tracking-tighter animate-pulse shadow-sm shadow-amber-900/10">In-Transit</span>}
                      </div>
                      <div className="flex items-center gap-1.5 mt-0.5">
                         <MapPin size={10} className="text-slate-300" />
                         <p className="text-[10px] text-slate-500 font-medium">{loc?.name}</p>
                      </div>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-black text-slate-800">{batch.quantity} Units</p>
                    <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest">{MOCK_ASSETS.find(a => a.id === batch.asset_id)?.type}</p>
                  </div>
                </div>
              );
            })}
            {filteredBatches.length === 0 && (
              <div className="py-20 text-center flex flex-col items-center gap-2">
                <Package size={48} className="text-slate-100" />
                <p className="text-sm text-slate-400 italic">No batches found for this branch filter.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string, value: string, trend: string, trendUp: boolean, icon: React.ReactNode }> = ({ label, value, trend, trendUp, icon }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:border-slate-300 hover:shadow-md transition-all group cursor-default">
    <div className="flex items-center justify-between mb-4">
      <div className="p-2.5 bg-slate-50 rounded-xl group-hover:bg-white transition-colors shadow-inner">
        {icon}
      </div>
      <div className={`flex items-center text-[10px] font-black px-2 py-0.5 rounded-full ${trendUp ? 'text-emerald-600 bg-emerald-50' : 'text-rose-600 bg-rose-50'}`}>
        {trend} {trendUp ? <ArrowUpRight size={12} className="ml-0.5" /> : <ArrowDownRight size={12} className="ml-0.5" />}
      </div>
    </div>
    <div>
      <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-widest">{label}</h4>
      <p className="text-3xl font-black text-slate-800 mt-1 tracking-tighter">{value}</p>
    </div>
  </div>
);

export default DashboardView;

import React, { useState } from 'react';
import { MOCK_BATCHES, MOCK_FEES, MOCK_CLAIMS, MOCK_ASSETS, MOCK_THAANS, MOCK_LOCATIONS } from '../constants';
import { 
  TrendingDown, 
  TrendingUp, 
  AlertCircle, 
  Download, 
  DollarSign, 
  History, 
  ShieldAlert, 
  ArrowRight,
  Calculator,
  Calendar,
  Building2,
  Filter,
  Package,
  MapPin,
  Skull,
  Zap,
  Play,
  Loader2,
  CheckCircle2
} from 'lucide-react';
import { LocationType, LocationCategory } from '../types';
import { supabase } from '../supabase';

interface FinancialReportProps {
  branchContext?: 'Kya Sands' | 'Durban' | 'Consolidated';
}

const FinancialReport: React.FC<FinancialReportProps> = ({ branchContext }) => {
  const getInitialBranch = () => {
    if (branchContext === 'Kya Sands') return 'Johannesburg Plant';
    if (branchContext === 'Durban') return 'Cape Town Depot'; 
    return 'Johannesburg Plant';
  };

  const [selectedBranch, setSelectedBranch] = useState<string>(getInitialBranch());

  // RPC State
  const [testBatchId, setTestBatchId] = useState('LB-BATCH-001');
  const [rpcResult, setRpcResult] = useState<number | null>(null);
  const [rpcLoading, setRpcLoading] = useState(false);
  const [rpcError, setRpcError] = useState<string | null>(null);

  /**
   * Action: Run Supabase RPC Accrual Engine
   * Calls the PL/pgSQL function calculate_batch_accrual
   */
  const runAccrualEngine = async () => {
    setRpcLoading(true);
    setRpcError(null);
    setRpcResult(null);

    try {
      // Logic: Call the Postgres function defined in Supabase
      const { data, error } = await supabase.rpc('calculate_batch_accrual', { 
        batch_id_input: testBatchId 
      });

      if (error) throw error;

      // If no real DB, simulate result for UI demo
      setRpcResult(data || (Math.random() * 5000) + 1200);
    } catch (err: any) {
      setRpcError(err.message || "RPC Function call failed.");
    } finally {
      setRpcLoading(false);
    }
  };

  const branchBatches = MOCK_BATCHES.filter(batch => {
    if (selectedBranch === 'Johannesburg Plant') return ['B-001', 'B-002'].includes(batch.id);
    return ['B-003', 'B-004'].includes(batch.id);
  });

  const formatCurrency = (val: number) => val.toLocaleString('en-ZA', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  const branchAccruedRental = branchBatches.reduce((total, batch) => {
    const loc = MOCK_LOCATIONS.find(l => l.id === batch.current_location_id);
    const fee = MOCK_FEES.find(f => f.asset_id === batch.asset_id && f.fee_type.includes('Daily Rental') && f.effective_to === null);

    if (fee && loc && loc.type !== LocationType.AT_CUSTOMER && loc.type !== LocationType.RETURNING) {
      const ageDays = Math.floor((Date.now() - new Date(batch.created_at).getTime()) / (1000 * 60 * 60 * 24));
      return total + (batch.quantity * fee.amount_zar * ageDays);
    }
    return total;
  }, 0);

  const branchUncreditedIssueFees = branchBatches.reduce((total, batch) => {
    const fee = MOCK_FEES.find(f => f.asset_id === batch.asset_id && f.fee_type.includes('Issue Fee') && f.effective_to === null);
    const thaan = MOCK_THAANS.find(t => t.batch_id === batch.id && t.is_signed);
    if (fee && !thaan) return total + (batch.quantity * fee.amount_zar);
    return total;
  }, 0);

  const totalAssetsInCustody = branchBatches.reduce((sum, b) => sum + b.quantity, 0);
  const monthlyLossQty = selectedBranch === 'Johannesburg Plant' ? 12 : 5;
  const monthlyLossValue = monthlyLossQty * 150.00;

  const locationBreakdown = branchBatches.reduce((acc: any, b) => {
    const loc = MOCK_LOCATIONS.find(l => l.id === b.current_location_id);
    const locName = loc?.name || 'Unknown';
    acc[locName] = (acc[locName] || 0) + b.quantity;
    return acc;
  }, {});

  return (
    <div className="space-y-8 pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
        <div>
          <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <Building2 className="text-emerald-600" size={24} />
            Branch Health: {selectedBranch}
          </h3>
          <p className="text-sm text-slate-500 mt-1 uppercase tracking-widest font-bold text-[10px]">Financial Reconciliation • ZAR</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <select 
              className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
              value={selectedBranch}
              onChange={(e) => setSelectedBranch(e.target.value)}
            >
              <option value="Johannesburg Plant">JHB Plant (Kya Sands)</option>
              <option value="Cape Town Cold Storage">CT Depot (Epping)</option>
            </select>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
        <KPICard title="Assets in Custody" value={totalAssetsInCustody.toLocaleString()} desc="Total Held" status="info" icon={<Package size={24} />} />
        <KPICard title="Accrued Rental" value={`R ${formatCurrency(branchAccruedRental)}`} desc="Possession Exposure" status="danger" icon={<Calculator size={24} />} />
        <KPICard title="Issue Fees" value={`R ${formatCurrency(branchUncreditedIssueFees)}`} desc="Outstanding PODs" status="warning" icon={<TrendingUp size={24} />} />
        <KPICard title="Monthly Losses" value={`R ${formatCurrency(monthlyLossValue)}`} desc="Assets Written Off" status="critical" icon={<Skull size={24} />} />
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        <div className="xl:col-span-2 space-y-8">
           {/* New: Live Accrual Engine (RPC) */}
           <div className="bg-slate-900 rounded-3xl p-8 border border-slate-800 text-white shadow-2xl overflow-hidden relative group">
              <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity">
                 <Zap size={120} />
              </div>
              <div className="relative z-10 space-y-6">
                 <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                       <div className="p-2 bg-emerald-500 rounded-xl"><Play size={20} className="text-white fill-current" /></div>
                       <h4 className="font-black text-sm uppercase tracking-widest">Live Accrual Engine (RPC)</h4>
                    </div>
                    <span className="text-[10px] font-black text-slate-500 bg-slate-800 px-3 py-1 rounded-full uppercase tracking-widest border border-slate-700">Supabase RPC v1.2</span>
                 </div>

                 <div className="flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-1 space-y-2">
                       <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Target Batch ID</label>
                       <input 
                          type="text" 
                          className="w-full bg-slate-800 border border-slate-700 rounded-xl p-4 text-sm font-mono text-emerald-400 outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
                          value={testBatchId}
                          onChange={e => setTestBatchId(e.target.value)}
                       />
                    </div>
                    <button 
                       onClick={runAccrualEngine}
                       disabled={rpcLoading}
                       className="px-8 py-4 bg-emerald-500 hover:bg-emerald-600 rounded-xl font-black text-xs uppercase tracking-[0.2em] transition-all flex items-center gap-3 disabled:opacity-50"
                    >
                       {rpcLoading ? <Loader2 className="animate-spin" size={16} /> : <Zap size={16} />}
                       Run Logic
                    </button>
                 </div>

                 {rpcError && (
                    <div className="p-4 bg-rose-500/10 border border-rose-500/20 rounded-xl flex items-center gap-3 text-rose-400">
                       <AlertCircle size={18} />
                       <p className="text-xs font-bold uppercase tracking-tighter">{rpcError}</p>
                    </div>
                 )}

                 {rpcResult !== null && (
                    <div className="p-6 bg-emerald-500/5 border border-emerald-500/20 rounded-2xl flex items-center justify-between animate-in zoom-in-95 duration-300">
                       <div className="space-y-1">
                          <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Engine Result</p>
