import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { supabase } from './supabase';
import { UserRole, User } from './types';

interface UserProfile {
  id: string;
  full_name: string;
  role_name: UserRole;
  home_branch_name: string;
  email: string;
}

interface UserContextType {
  user: any;
  profile: UserProfile | null;
  isLoading: boolean;
  logout: () => Promise<void>;
  hasPermission: (permission: string) => boolean;
}

const UserContext = createContext<UserContextType | undefined>(undefined);

export const UserProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  const fetchProfile = async (userId: string) => {
    try {
      // In a real Supabase RLS setup, we query our public 'profiles' or 'users' table
      // which is linked to auth.users. Here we simulate the join for role_name and home_branch_name.
      const { data, error } = await supabase
        .from('users')
        .select(`
          id, 
          full_name, 
          home_branch_name,
          user_roles (role_name)
        `)
        .eq('id', userId)
        .single();

      if (error) throw error;

      const profileData: UserProfile = {
        id: data.id,
        full_name: data.full_name,
        // Assuming a many-to-one or one-to-one join with user_roles
        role_name: (data.user_roles as any)?.role_name || UserRole.STAFF,
        home_branch_name: data.home_branch_name || 'Consolidated',
        email: user?.email || '',
      };

      setProfile(profileData);
    } catch (err) {
      console.error("Error fetching user profile:", err);
      // Fallback for demonstration if tables aren't set up yet
      setProfile({
        id: userId,
        full_name: "Mock User",
        role_name: UserRole.STAFF,
        home_branch_name: 'Kya Sands',
        email: 'user@lupobakery.co.za'
      });
    }
  };

  useEffect(() => {
    // 1. Initial Session Check
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
      if (session?.user) fetchProfile(session.user.id);
      else setIsLoading(false);
    });

    // 2. Auth Listener
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
      if (session?.user) {
        fetchProfile(session.user.id);
      } else {
        setProfile(null);
        setIsLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (profile) setIsLoading(false);
  }, [profile]);

  const logout = async () => {
    await supabase.auth.signOut();
  };

  const hasPermission = (permission: string): boolean => {
    if (!profile) return false;
    const role = profile.role_name;

    // Executive: Read-only access
    if (role === UserRole.EXECUTIVE) {
      return ['VIEW_DASHBOARD', 'VIEW_SETTLEMENT'].includes(permission);
    }

    // Crates Dept (Staff): Hide financials
    if (role === UserRole.STAFF) {
      return ['WRITE_MOVEMENTS', 'MANAGE_LOSSES', 'VIEW_DASHBOARD'].includes(permission);
    }

    // Manager/Admin: Full access (with branch restrictions handled in UI)
    return true;
  };

  return (
    <UserContext.Provider value={{ user, profile, isLoading, logout, hasPermission }}>
      {children}
    </UserContext.Provider>
  );
};

export const useUser = () => {
  const context = useContext(UserContext);
  if (context === undefined) {
    throw new Error('useUser must be used within a UserProvider');
  }
  return context;
};

